 35Ôćĺ
 36Ôćĺconst execFileAsync = promisify(execFile);
 37Ôćĺ
 38Ôćĺtype Env = { Variables: { workspace: WorkspaceWithDetailsRow; workspacePath: string } };
 39Ôćĺconst app = new Hono<Env>();
 40Ôćĺ
 41Ôćĺapp.get("/workspaces", (c) => {
 42Ôćĺ  const db = getDatabase();
 43Ôćĺ  const workspaces = getAllWorkspaces(db);
 44Ôćĺ  return c.json(workspaces.map((ws) => ({ ...ws, workspace_path: computeWorkspacePath(ws) })));
 45Ôćĺ});
