 47Ôćĺapp.get("/workspaces/by-repo", (c) => {
 48Ôćĺ  const db = getDatabase();
 49Ôćĺ  const stateParam = c.req.query("state");
 50Ôćĺ  const workspaces = getWorkspacesByRepo(db, stateParam);
 51Ôćĺ
 52Ôćĺ  const grouped: Record<string, any> = {};
 53Ôćĺ  workspaces.forEach((workspace) => {
 54Ôćĺ    const repoId = workspace.repository_id || "unknown";
 55Ôćĺ    if (!grouped[repoId]) {
 56Ôćĺ      grouped[repoId] = {
 57Ôćĺ        repo_id: repoId,
 58Ôćĺ        repo_name: workspace.repo_name || "Unknown",
 59Ôćĺ        sort_order: workspace.repo_sort_order || 999,
 60Ôćĺ        workspaces: [],
 61Ôćĺ      };
 62Ôćĺ    }
 63Ôćĺ    grouped[repoId].workspaces.push({
 64Ôćĺ      ...workspace,
 65Ôćĺ      workspace_path: computeWorkspacePath(workspace),
 66Ôćĺ    });
 67Ôćĺ  });
 68Ôćĺ
 69Ôćĺ  // Backfill repos that have no matching workspaces (e.g. all archived)
 70Ôćĺ  // so they still appear in the sidebar.
 71Ôćĺ  const allRepos = getAllRepositorySummaries(db);
 72Ôćĺ  for (const repo of allRepos) {
 73Ôćĺ    if (!grouped[repo.id]) {
 74Ôćĺ      grouped[repo.id] = {
 75Ôćĺ        repo_id: repo.id,
 76Ôćĺ        repo_name: repo.name,
 77Ôćĺ        sort_order: repo.sort_order ?? 999,
 78Ôćĺ        workspaces: [],
 79Ôćĺ      };
 80Ôćĺ    }
 81Ôćĺ  }
 82Ôćĺ
 83Ôćĺ  const result = Object.values(grouped).sort((a: any, b: any) => a.sort_order - b.sort_order);
 84Ôćĺ  return c.json(result);
 85Ôćĺ});
