 87Ôćĺapp.get("/workspaces/:id", (c) => {
 88Ôćĺ  const db = getDatabase();
 89Ôćĺ  const workspace = getWorkspaceById(db, c.req.param("id"));
 90Ôćĺ  if (!workspace) throw new NotFoundError("Workspace not found");
 91Ôćĺ  return c.json({ ...workspace, workspace_path: computeWorkspacePath(workspace) });
 92Ôćĺ});
 93Ôćĺ
 94Ôćĺapp.patch("/workspaces/:id", async (c) => {
 95Ôćĺ  const db = getDatabase();
 96Ôćĺ  const { state } = parseBody(PatchWorkspaceBody, await c.req.json());
 97Ôćĺ  if (state) {
 98Ôćĺ    db.prepare("UPDATE workspaces SET state = ? WHERE id = ?").run(state, c.req.param("id"));
 99Ôćĺ
100Ôćĺ    // Run archive lifecycle hook (best-effort)
101Ôćĺ    if (state === "archived") {
102Ôćĺ      try {
103Ôćĺ        const ws = getWorkspaceById(db, c.req.param("id"));
104Ôćĺ        if (ws && ws.root_path) {
105Ôćĺ          const wsPath = computeWorkspacePath(ws);
106Ôćĺ          const manifest = readManifestWithFallback(wsPath, ws.root_path);
107Ôćĺ          const archiveCmd = manifest ? getArchiveCommand(manifest) : null;
108Ôćĺ          if (archiveCmd) {
109Ôćĺ            const archiveEnv = getOpenDevsEnv(manifest!, {
110Ôćĺ              id: ws.id,
111Ôćĺ              rootPath: ws.root_path,
112Ôćĺ              workspacePath: wsPath,
113Ôćĺ            });
114Ôćĺ            const archiveProc = spawn("sh", ["-c", archiveCmd], {
115Ôćĺ              cwd: wsPath,
116Ôćĺ              env: { ...process.env, ...archiveEnv },
117Ôćĺ              stdio: "ignore",
118Ôćĺ              detached: false,
119Ôćĺ            });
120Ôćĺ            archiveProc.on("error", (err) => {
121Ôćĺ              console.error(`Archive hook error for workspace ${c.req.param("id")}:`, err.message);
122Ôćĺ            });
123Ôćĺ            archiveProc.unref();
124Ôćĺ          }
125Ôćĺ        }
126Ôćĺ      } catch (err) {
127Ôćĺ        console.warn("[WORKSPACE] Archive lifecycle hook failed (continuing):", err);
128Ôćĺ      }
129Ôćĺ    }
130Ôćĺ  }
131Ôćĺ  const updated = getWorkspaceRaw(db, c.req.param("id"));
132Ôćĺ  invalidate(["workspaces", "sessions", "stats"]);
133Ôćĺ  return c.json(updated);
134Ôćĺ});
135Ôćĺ
136Ôćĺ// Create workspace
137Ôćĺapp.post("/workspaces", async (c) => {
138Ôćĺ  const db = getDatabase();
139Ôćĺ  const { repository_id } = parseBody(CreateWorkspaceBody, await c.req.json());
140Ôćĺ
141Ôćĺ  const repo = getRepositoryById(db, repository_id);
142Ôćĺ  if (!repo) throw new NotFoundError("Repository not found");
143Ôćĺ
144Ôćĺ  const workspace_name = generateUniqueName(db);
145Ôćĺ  const parent_branch = repo.git_default_branch || "main";
146Ôćĺ  const workspaceId = uuidv7();
147Ôćĺ
148Ôćĺ  let branchPrefix = "workspace";
149Ôćĺ  try {
150Ôćĺ    const gitUser = execSync("git config user.name", { cwd: repo.root_path!, encoding: "utf8" })
151Ôćĺ      .trim()
152Ôćĺ      .toLowerCase()
153Ôćĺ      .replace(/[^a-z0-9_-]/g, "-");
154Ôćĺ    if (gitUser) branchPrefix = gitUser;
155Ôćĺ  } catch {}
156Ôćĺ  const placeholderBranchName = `${branchPrefix}/${workspace_name}`;
157Ôćĺ
158Ôćĺ  // ÔöÇÔöÇÔöÇ IMPORTANT: Remote-first branch strategy ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
159Ôćĺ  // We ALWAYS want worktrees branched from origin/<parent_branch>, not
160Ôćĺ  // local <parent_branch>. Diffs are computed against origin/<branch>
161Ôćĺ  // (see resolve_parent_branch in git.rs and git.service.ts). If origin
162Ôćĺ  // is stale, the merge-base drifts and every file since the divergence
163Ôćĺ  // shows as "changed" ÔÇö producing hundreds of phantom file changes.
164Ôćĺ  //
165Ôćĺ  // Fetch the remote branch before creating the worktree so that:
166Ôćĺ  // 1. The worktree starts from the latest upstream commit
167Ôćĺ  // 2. Diff merge-base matches what we branched from (zero phantom changes)
168Ôćĺ  // 3. PRs will be clean against the upstream target
169Ôćĺ  //
170Ôćĺ  // This is a non-blocking fetch (~1-3s on a warm connection). Workspace
171Ôćĺ  // creation is already async (worktree add runs in a child process) and
172Ôćĺ  // correctness matters more here.
173Ôćĺ  // ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
174Ôćĺ  try {
175Ôćĺ    await execFileAsync("git", ["fetch", "origin", parent_branch], {
176Ôćĺ      cwd: repo.root_path!,
177Ôćĺ      timeout: 15000,
178Ôćĺ    });
179Ôćĺ  } catch (fetchErr) {
180Ôćĺ    // Non-fatal: if fetch fails (offline, no remote, etc.), fall back to
181Ôćĺ    // whatever local state we have. The worktree will still be created
182Ôćĺ    // from the local branch ÔÇö diffs might be off but it's better than
183Ôćĺ    // blocking workspace creation entirely.
184Ôćĺ    console.warn(
185Ôćĺ      `[WORKSPACE] git fetch origin ${parent_branch} failed (continuing with local):`,
186Ôćĺ      fetchErr
187Ôćĺ    );
188Ôćĺ  }
189Ôćĺ
190Ôćĺ  db.prepare(
191Ôćĺ    `
192Ôćĺ    INSERT INTO workspaces (
193Ôćĺ      id, repository_id, slug, git_branch,
194Ôćĺ      git_target_branch, state, updated_at
195Ôćĺ    ) VALUES (?, ?, ?, ?, ?, ?, datetime('now'))
196Ôćĺ  `
197Ôćĺ  ).run(
198Ôćĺ    workspaceId,
199Ôćĺ    repository_id,
200Ôćĺ    workspace_name,
201Ôćĺ    placeholderBranchName,
202Ôćĺ    parent_branch,
203Ôćĺ    "initializing"
204Ôćĺ  );
205Ôćĺ
206Ôćĺ  // Branch from origin/<parent_branch> when available (fetched above).
207Ôćĺ  // Falls back to local <parent_branch> if remote doesn't exist.
208Ôćĺ  const worktreeBase = await (async () => {
209Ôćĺ    try {
210Ôćĺ      await execFileAsync(
211Ôćĺ        "git",
212Ôćĺ        ["show-ref", "--verify", "--quiet", `refs/remotes/origin/${parent_branch}`],
213Ôćĺ        {
214Ôćĺ          cwd: repo.root_path!,
215Ôćĺ          timeout: 2000,
216Ôćĺ        }
217Ôćĺ      );
218Ôćĺ      return `origin/${parent_branch}`;
219Ôćĺ    } catch {
220Ôćĺ      return parent_branch;
221Ôćĺ    }
222Ôćĺ  })();
223Ôćĺ
224Ôćĺ  const workspacePath = path.join(repo.root_path!, ".opendevs", workspace_name);
225Ôćĺ
226Ôćĺ  // Fire-and-forget: run the init pipeline async (don't await).
227Ôćĺ  // Pipeline handles: worktree creation Ôćĺ deps install Ôćĺ .env copy Ôćĺ session creation.
228Ôćĺ  // Progress events flow: stdout Ôćĺ Electron main process Ôćĺ IPC events Ôćĺ Frontend.
229Ôćĺ  // On fatal failure: reverse cleanup (rm dir, prune worktree, delete branch).
230Ôćĺ  initializeWorkspace({
231Ôćĺ    workspaceId,
232Ôćĺ    repositoryId: repository_id,
233Ôćĺ    repoRootPath: repo.root_path!,
234Ôćĺ    workspacePath,
235Ôćĺ    branchName: placeholderBranchName,
236Ôćĺ    worktreeBase,
237Ôćĺ    parentBranch: parent_branch,
238Ôćĺ  })
239Ôćĺ    .then(() => {
240Ôćĺ      // Workspace is ready ÔÇö check for manifest setup script
241Ôćĺ      const manifest = readManifestWithFallback(workspacePath, repo.root_path!);
242Ôćĺ      const setupCmd = manifest ? getSetupCommand(manifest) : null;
243Ôćĺ      if (setupCmd && manifest) {
244Ôćĺ        db.prepare("UPDATE workspaces SET setup_status = 'running' WHERE id = ?").run(workspaceId);
245Ôćĺ        const setupEnv = getOpenDevsEnv(manifest, {
246Ôćĺ          id: workspaceId,
247Ôćĺ          rootPath: repo.root_path!,
248Ôćĺ          workspacePath,
249Ôćĺ        });
250Ôćĺ        runSetupScript(db, workspaceId, setupCmd, setupEnv, workspacePath);
251Ôćĺ      }
252Ôćĺ    })
253Ôćĺ    .catch((err) => {
254Ôćĺ      // Belt-and-suspenders: initializeWorkspace handles its own errors,
255Ôćĺ      // but if something truly unexpected escapes, don't leave workspace stuck.
256Ôćĺ      console.error("[WORKSPACE] Unhandled init pipeline error:", err);
257Ôćĺ      try {
258Ôćĺ        db.prepare(
259Ôćĺ          "UPDATE workspaces SET state = 'error', init_stage = 'unhandled', error_message = 'Unhandled init pipeline error' WHERE id = ? AND state = 'initializing'"
260Ôćĺ        ).run(workspaceId);
261Ôćĺ        invalidate(["workspaces", "stats"]);
262Ôćĺ      } catch {}
263Ôćĺ    });
264Ôćĺ
265Ôćĺ  const workspace = getWorkspaceForMiddleware(db, workspaceId);
266Ôćĺ  if (!workspace) throw new NotFoundError("Workspace not found after creation");
267Ôćĺ
268Ôćĺ  // Push immediately so clients see the workspace in 'initializing' state.
269Ôćĺ  // Query-protocol subscribers get snapshots + q:invalidate for unmounted caches.
270Ôćĺ  // The init pipeline will invalidate again when it transitions to 'ready'.
271Ôćĺ  invalidate(["workspaces", "stats"]);
272Ôćĺ
273Ôćĺ  return c.json({ ...workspace, workspace_path: computeWorkspacePath(workspace) });
274Ôćĺ});
275Ôćĺ
276Ôćĺ// List all sessions for a workspace (used by chat tab reconstruction)
277Ôćĺapp.get("/workspaces/:id/sessions", (c) => {
278Ôćĺ  const db = getDatabase();
279Ôćĺ  const workspaceId = c.req.param("id");
280Ôćĺ  const workspace = getWorkspaceRaw(db, workspaceId);
281Ôćĺ  if (!workspace) throw new NotFoundError("Workspace not found");
282Ôćĺ  const sessions = getSessionsByWorkspaceId(db, workspaceId);
283Ôćĺ  return c.json(sessions);
284Ôćĺ});
