286Ôćĺ// Create a new session for an existing workspace
287Ôćĺapp.post("/workspaces/:id/sessions", (c) => {
288Ôćĺ  const db = getDatabase();
289Ôćĺ  const workspaceId = c.req.param("id");
290Ôćĺ
291Ôćĺ  const workspace = getWorkspaceRaw(db, workspaceId);
292Ôćĺ  if (!workspace) throw new NotFoundError("Workspace not found");
293Ôćĺ
294Ôćĺ  const sessionId = uuidv7();
295Ôćĺ
296Ôćĺ  const createSession = db.transaction(() => {
297Ôćĺ    db.prepare(
298Ôćĺ      "INSERT INTO sessions (id, workspace_id, status, updated_at) VALUES (?, ?, 'idle', datetime('now'))"
299Ôćĺ    ).run(sessionId, workspaceId);
300Ôćĺ
301Ôćĺ    db.prepare(
302Ôćĺ      "UPDATE workspaces SET current_session_id = ?, updated_at = datetime('now') WHERE id = ?"
303Ôćĺ    ).run(sessionId, workspaceId);
304Ôćĺ  });
305Ôćĺ
306Ôćĺ  createSession();
307Ôćĺ  invalidate(["workspaces", "sessions", "stats"]);
308Ôćĺ
309Ôćĺ  const session = getSessionRaw(db, sessionId);
310Ôćĺ  return c.json(session);
311Ôćĺ});
