340Ôćĺ  }
341Ôćĺ
342Ôćĺ  // Re-read manifest (AI agent may have fixed it, or it was added to repo root via settings)
343Ôćĺ  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
344Ôćĺ  const setupCmd = manifest ? getSetupCommand(manifest) : null;
345Ôćĺ  if (!setupCmd || !manifest) {
346Ôćĺ    db.prepare(
