  1Ôćĺ// backend/src/services/query-engine.ts
  2Ôćĺ// Query engine ÔÇö handles q:* protocol frames for typed reactive queries.
  3Ôćĺ// Module singleton: subscription state + dispatch logic.
  4Ôćĺ// Works for both local WS and relay-tunneled connections via WsSendable.
  5Ôćĺ//
  6Ôćĺ// Subscription model: ID-keyed. Client assigns IDs ("sub_1", "sub_2") and
  7Ôćĺ// server echoes them back on q:snapshot/q:delta so the client can route
  8Ôćĺ// to the correct callback.
  9Ôćĺ
 10Ôćĺimport { match } from "ts-pattern";
 11Ôćĺimport { getDatabase } from "../lib/database";
 12Ôćĺimport {
 13Ôćĺ  getDashboardWorkspaces,
 14Ôćĺ  getStats,
 15Ôćĺ  getSessionsByWorkspaceId,
 16Ôćĺ  getSessionById,
 17Ôćĺ  getMessages,
 18Ôćĺ  hasOlderMessages,
 19Ôćĺ  hasNewerMessages,
 20Ôćĺ  getWorkspaceRaw,
 21Ôćĺ  getMaxMessageSeq,
 22Ôćĺ  getMessagesDelta,
 23Ôćĺ  resetStatsCache,
 24Ôćĺ  getWorkspacesByRepo,
 25Ôćĺ  getWorkspacesBySessionIds,
 26Ôćĺ  getAllRepositorySummaries,
 27Ôćĺ} from "../db";
 28Ôćĺimport { computeWorkspacePath } from "../middleware/workspace-loader";
 29Ôćĺimport { getConnection } from "./ws.service";
 30Ôćĺimport { resolveToolRelay, rejectToolRelay, runCommand } from "./agent";
 31Ôćĺimport {
 32Ôćĺ  QUERY_RESOURCES,
 33Ôćĺ  MUTATION_NAMES,
 34Ôćĺ  COMMAND_NAMES,
 35Ôćĺ  type MutationName,
 36Ôćĺ  type CommandName,
 37Ôćĺ  type QueryResource,
 38Ôćĺ  type QServerFrame,
 39Ôćĺ} from "@shared/types/query-protocol";
 40Ôćĺ
 41Ôćĺ// ---- Subscription State ----
 42Ôćĺ
 43Ôćĺtype QueryParams = Record<string, unknown>;
 44Ôćĺ
 45Ôćĺinterface ResourceFrameInput {
 46Ôćĺ  id: string;
 47Ôćĺ  resource: string;
 48Ôćĺ  params: QueryParams;
 49Ôćĺ}
 50Ôćĺ
 51Ôćĺinterface UnsubscribeFrameInput {
 52Ôćĺ  id: string;
 53Ôćĺ}
 54Ôćĺ
 55Ôćĺinterface MutateFrameInput {
 56Ôćĺ  id: string;
 57Ôćĺ  action: string;
 58Ôćĺ  params: QueryParams;
 59Ôćĺ}
 60Ôćĺ
 61Ôćĺinterface CommandFrameInput {
 62Ôćĺ  id: string;
 63Ôćĺ  command: string;
 64Ôćĺ  params: QueryParams;
 65Ôćĺ}
 66Ôćĺ
 67Ôćĺinterface Sub {
 68Ôćĺ  id: string;
 69Ôćĺ  resource: QueryResource;
 70Ôćĺ  params: QueryParams;
 71Ôćĺ}
 72Ôćĺ
 73Ôćĺ/** Per-connection active subscriptions, keyed by client-assigned sub ID. */
 74Ôćĺconst subs = new Map<string, Map<string, Sub>>();
 75Ôćĺ
 76Ôćĺ/** For messages: track last seen seq per subscription for delta push.
 77Ôćĺ *  Key: `${connectionId}:${subId}` Ôćĺ lastSeq */
 78Ôćĺconst messageCursors = new Map<string, number>();
 79Ôćĺ
 80Ôćĺ// ---- Public API ----
 81Ôćĺ
 82Ôćĺ/**
 83Ôćĺ * Handle an incoming q:* frame from an authenticated connection.
 84Ôćĺ * Registered as onQueryFrame in ws.service protocol handlers.
 85Ôćĺ */
 86Ôćĺexport function handleFrame(connectionId: string, msg: QueryParams): void {
 87Ôćĺ  const type = typeof msg.type === "string" ? msg.type : "unknown";
 88Ôćĺ
 89Ôćĺ  try {
 90Ôćĺ    match(type)
 91Ôćĺ      .with("q:request", () => {
 92Ôćĺ        handleRequest(connectionId, parseResourceFrame(msg));
 93Ôćĺ      })
 94Ôćĺ      .with("q:subscribe", () => {
 95Ôćĺ        handleSubscribe(connectionId, parseResourceFrame(msg));
 96Ôćĺ      })
 97Ôćĺ      .with("q:unsubscribe", () => {
 98Ôćĺ        handleUnsubscribe(connectionId, parseUnsubscribeFrame(msg));
 99Ôćĺ      })
100Ôćĺ      .with("q:mutate", () => {
101Ôćĺ        handleMutate(connectionId, parseMutateFrame(msg));
102Ôćĺ      })
103Ôćĺ      .with("q:command", () => {
104Ôćĺ        handleCommand(connectionId, parseCommandFrame(msg));
105Ôćĺ      })
106Ôćĺ      .with("q:tool_response", () => {
107Ôćĺ        handleToolResponse(msg);
108Ôćĺ      })
109Ôćĺ      .otherwise(() => {
110Ôćĺ        sendFrame(connectionId, {
111Ôćĺ          type: "q:error",
112Ôćĺ          id: getFrameId(msg),
113Ôćĺ          code: "UNKNOWN_FRAME",
114Ôćĺ          message: `Unknown query frame type: ${type}`,
115Ôćĺ        });
116Ôćĺ      });
117Ôćĺ  } catch (err) {
118Ôćĺ    sendFrame(connectionId, {
119Ôćĺ      type: "q:error",
120Ôćĺ      id: getFrameId(msg),
121Ôćĺ      code: "INVALID_FRAME",
122Ôćĺ      message: err instanceof Error ? err.message : "Invalid query frame",
123Ôćĺ    });
124Ôćĺ  }
125Ôćĺ}
126Ôćĺ
127Ôćĺ/** Remove all subscriptions for a connection (cleanup on disconnect). */
128Ôćĺexport function removeSubs(connectionId: string): void {
129Ôćĺ  const connSubs = subs.get(connectionId);
130Ôćĺ  if (connSubs) {
131Ôćĺ    for (const [subId, sub] of connSubs) {
132Ôćĺ      if (sub.resource === "messages") {
133Ôćĺ        messageCursors.delete(`${connectionId}:${subId}`);
134Ôćĺ      }
135Ôćĺ    }
136Ôćĺ    subs.delete(connectionId);
137Ôćĺ  }
138Ôćĺ}
139Ôćĺ
140Ôćĺ/** Optional context for targeted invalidation (e.g., which sessions changed). */
141Ôćĺinterface InvalidateContext {
142Ôćĺ  sessionIds?: string[];
143Ôćĺ}
144Ôćĺ
145Ôćĺ/**
146Ôćĺ * Push-first invalidation: re-run queries for active subscribers and push
147Ôćĺ * fresh snapshots or deltas.
148Ôćĺ *
149Ôćĺ * Messages use q:delta (cursor-based) instead of full snapshots.
150Ôćĺ * When `ctx.sessionIds` is provided, workspace subscribers receive a targeted

150Ôćĺ * When `ctx.sessionIds` is provided, workspace subscribers receive a targeted
151Ôćĺ * q:delta (only the changed workspaces) instead of a full q:snapshot.
152Ôćĺ */
153Ôćĺexport function invalidate(resources: QueryResource[], ctx?: InvalidateContext): void {
154Ôćĺ  if (resources.includes("stats")) {
155Ôćĺ    resetStatsCache();
156Ôćĺ  }
157Ôćĺ
158Ôćĺ  // Phase 1: Push fresh data to active subscribers
159Ôćĺ  for (const [connectionId, connSubs] of subs) {
160Ôćĺ    if (!getConnection(connectionId)) {
161Ôćĺ      removeSubs(connectionId);
162Ôćĺ      continue;
163Ôćĺ    }
164Ôćĺ
165Ôćĺ    for (const [subId, sub] of connSubs) {
166Ôćĺ      if (!resources.includes(sub.resource)) continue;
167Ôćĺ
168Ôćĺ      if (sub.resource === "messages") {
169Ôćĺ        // Messages: push delta (new messages since last cursor)
170Ôćĺ        pushMessageDelta(connectionId, subId, sub.params);
171Ôćĺ      } else if (sub.resource === "workspaces" && ctx?.sessionIds?.length) {
172Ôćĺ        // Workspaces with session context: try targeted delta
173Ôćĺ        try {
174Ôćĺ          const db = getDatabase();
175Ôćĺ          const stateFilter = readStringParam(sub.params, "state") ?? "ready,initializing";
176Ôćĺ          const allowedStates = new Set(stateFilter.split(",").map((s) => s.trim()));
177Ôćĺ          const changedWorkspaces = getWorkspacesBySessionIds(db, ctx.sessionIds).filter((ws) =>
178Ôćĺ            allowedStates.has(ws.state)
179Ôćĺ          );
180Ôćĺ          if (changedWorkspaces.length > 0) {
181Ôćĺ            const withPaths = changedWorkspaces.map((ws) => ({
182Ôćĺ              ...ws,
183Ôćĺ              workspace_path: computeWorkspacePath(ws),
184Ôćĺ            }));
185Ôćĺ            sendFrame(connectionId, {
186Ôćĺ              type: "q:delta",
187Ôćĺ              id: subId,
188Ôćĺ              upserted: withPaths,
189Ôćĺ            });
190Ôćĺ          } else {
191Ôćĺ            // Session IDs didn't match any workspaces ÔÇö fall back to full snapshot
192Ôćĺ            const data = runQuery(sub.resource, sub.params);
193Ôćĺ            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
194Ôćĺ          }
195Ôćĺ        } catch (err) {
196Ôćĺ          // Delta lookup failed ÔÇö fall back to full snapshot
197Ôćĺ          console.error(`[QueryEngine] Workspace delta failed, falling back to snapshot:`, err);
198Ôćĺ          try {
199Ôćĺ            const data = runQuery(sub.resource, sub.params);
200Ôćĺ            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
201Ôćĺ          } catch (snapErr) {
202Ôćĺ            console.error(`[QueryEngine] Snapshot fallback also failed:`, snapErr);
203Ôćĺ          }
204Ôćĺ        }
205Ôćĺ      } else if (sub.resource === "session" && ctx?.sessionIds?.length) {
206Ôćĺ        // Session with context: only push if this subscription's session is in the changed set
207Ôćĺ        const subscribedSessionId = readStringParam(sub.params, "sessionId");
208Ôćĺ        if (subscribedSessionId && ctx.sessionIds.includes(subscribedSessionId)) {
209Ôćĺ          try {
210Ôćĺ            const data = runQuery(sub.resource, sub.params);
211Ôćĺ            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
212Ôćĺ          } catch (err) {
213Ôćĺ            console.error(`[QueryEngine] Session snapshot push failed:`, err);
214Ôćĺ          }
215Ôćĺ        }
216Ôćĺ        // If session not in changed set, skip the push
217Ôćĺ      } else {
218Ôćĺ        // Other resources: push full snapshot
219Ôćĺ        try {
220Ôćĺ          const data = runQuery(sub.resource, sub.params);
221Ôćĺ          sendFrame(connectionId, {
222Ôćĺ            type: "q:snapshot",
223Ôćĺ            id: subId,
224Ôćĺ            data,
225Ôćĺ          });
226Ôćĺ        } catch (err) {
227Ôćĺ          console.error(`[QueryEngine] Snapshot push failed for ${sub.resource}:`, err);
228Ôćĺ        }
229Ôćĺ      }
230Ôćĺ    }
231Ôćĺ  }
232Ôćĺ}
