  1Ôćĺ/**
  2Ôćĺ * Sidebar Status Configuration System
  3Ôćĺ *
  4Ôćĺ * Centralized configuration for workspace/session statuses, priorities, and visual styling.
  5Ôćĺ * Design philosophy: Make it easy to iterate on colors and priorities without touching component code.
  6Ôćĺ *
  7Ôćĺ * @see src/features/session/types.ts for SessionStatus type definition
  8Ôćĺ */
  9Ôćĺ
 10Ôćĺimport type { Workspace } from "@/features/workspace/types";
 11Ôćĺ
 12Ôćĺ/**
 13Ôćĺ * Display status extends SessionStatus with derived states.
 14Ôćĺ * 'unread' is derived from needs_response / needs_plan_response session status.
 15Ôćĺ */
 16Ôćĺexport type DisplayStatus = "idle" | "working" | "error" | "unread";
 17Ôćĺ
 18Ôćĺ/**
 19Ôćĺ * Priority levels for sorting (higher = more urgent)
 20Ôćĺ */
 21Ôćĺexport enum StatusPriority {
 22Ôćĺ  ERROR = 4, // Critical - something broke
 23Ôćĺ  UNREAD = 3, // Important - needs review / response
 24Ôćĺ  WORKING = 2, // Active - in progress
 25Ôćĺ  IDLE = 0, // Dormant - no activity
 26Ôćĺ}
 27Ôćĺ
 28Ôćĺ/**
 29Ôćĺ * Visual configuration for each status
 30Ôćĺ *
 31Ôćĺ * Design System:
 32Ôćĺ * - badge: Color for notification badges (collapsed sidebar)
 33Ôćĺ * - border: Border/glow color for active states
 34Ôćĺ * - text: Text color for status labels
 35Ôćĺ * - bg: Background color for sections/cards
 36Ôćĺ *
 37Ôćĺ * Color Semantics:
 38Ôćĺ * ­čö┤ Red (error) = Critical, blocking, needs immediate action
 39Ôćĺ * ­ččí Amber (unread) = Important, needs attention when ready
 40Ôćĺ * ­ččó Green (working) = Active, positive, making progress
 41Ôćĺ * ­ččú Purple (compacting) = Transient, maintenance, ignore
 42Ôćĺ * ÔÜ¬ Gray (idle) = Dormant, background, low priority
 43Ôćĺ */
 44Ôćĺexport interface StatusConfig {
 45Ôćĺ  priority: StatusPriority;
 46Ôćĺ  label: string;
 47Ôćĺ  labelActive: string; // Present continuous form (e.g., "Working...")
 48Ôćĺ  badge: string; // Tailwind classes for badge
 49Ôćĺ  border: string; // Tailwind classes for border/glow
 50Ôćĺ  text: string; // Tailwind classes for text
 51Ôćĺ  bg: string; // Tailwind classes for background
 52Ôćĺ  pulse?: boolean; // Whether to animate/pulse
 53Ôćĺ}
 54Ôćĺ
 55Ôćĺ/**
 56Ôćĺ * Status configuration map
 57Ôćĺ *
 58Ôćĺ * IMPORTANT: To change colors, edit this object (no component changes needed)
 59Ôćĺ */
 60Ôćĺexport const STATUS_CONFIG: Record<DisplayStatus, StatusConfig> = {
 61Ôćĺ  error: {
 62Ôćĺ    priority: StatusPriority.ERROR,
 63Ôćĺ    label: "Error",
