260Ôćĺ/**
261Ôćĺ * Fetch PR status for a workspace.
262Ôćĺ *
263Ôćĺ * Gated on gh CLI being installed + authenticated (like Codex).
264Ôćĺ * Polls every 30s while agent is working (to detect PR creation),
265Ôćĺ * 60s while CI is pending post-session (CI runs 2-15min after push),
266Ôćĺ * stops polling otherwise.
267Ôćĺ */
268Ôćĺexport function usePRStatus(
269Ôćĺ  workspaceId: string | null,
270Ôćĺ  options?: { ghInstalled?: boolean; ghAuthenticated?: boolean; sessionStatus?: string }
271Ôćĺ) {
272Ôćĺ  const { ghInstalled = true, ghAuthenticated = true, sessionStatus } = options ?? {};
273Ôćĺ  return useQuery({
274Ôćĺ    queryKey: queryKeys.workspaces.prStatus(workspaceId || ""),
275Ôćĺ    queryFn: () => WorkspaceService.fetchPRStatus(workspaceId!),
276Ôćĺ    enabled: !!workspaceId && ghInstalled && ghAuthenticated,
277Ôćĺ    staleTime: 10_000,
278Ôćĺ    refetchInterval: (query) => {
279Ôćĺ      // While agent is working: poll every 30s to detect PR creation/updates.
280Ôćĺ      if (sessionStatus === "working") return 30_000;
281Ôćĺ
282Ôćĺ      // After agent stops: CI checks typically run 2-15min. Poll every 60s
283Ôćĺ      // while CI is pending so the user sees updates without manual refresh.
284Ôćĺ      const data = query.state.data as PRStatus | null | undefined;
285Ôćĺ      if (data?.has_pr && data?.ci_status === "pending") return 60_000;
286Ôćĺ
287Ôćĺ      // No PR or CI resolved: stop polling. Window focus refetch handles edge cases.
288Ôćĺ      return false;
289Ôćĺ    },
290Ôćĺ    refetchOnWindowFocus: true,
291Ôćĺ  });
292Ôćĺ}
