471Ôćĺ/**
472Ôćĺ * Update system prompt mutation with optimistic update
473Ôćĺ */
474Ôćĺexport function useUpdateSystemPrompt() {
475Ôćĺ  const queryClient = useQueryClient();
476Ôćĺ
477Ôćĺ  return useMutation({
478Ôćĺ    mutationFn: ({ workspaceId, systemPrompt }: { workspaceId: string; systemPrompt: string }) =>
479Ôćĺ      WorkspaceService.updateSystemPrompt(workspaceId, systemPrompt),
480Ôćĺ
481Ôćĺ    // Optimistic update: Show new prompt immediately
