  3Ôćĺ//
  4Ôćĺ// Domain constants (QUERY_RESOURCES, MUTATION_NAMES, COMMAND_NAMES, PROTOCOL_EVENTS)
  5Ôćĺ// live in shared/events.ts ÔÇö the single source of truth for all app events
  6Ôćĺ// and resources. This file only defines the wire format that carries them.
  7Ôćĺ
  8Ôćĺimport type { QueryResource, MutationName, CommandName, ProtocolEvent } from "../events";
  9Ôćĺ
 10Ôćĺ// Re-export so existing `import { QueryResource } from "query-protocol"` still works.
 11Ôćĺexport type { QueryResource, MutationName, CommandName, ProtocolEvent };
 12Ôćĺexport { QUERY_RESOURCES, MUTATION_NAMES, COMMAND_NAMES, PROTOCOL_EVENTS } from "../events";
 13Ôćĺ
 14Ôćĺ// ---- Client Ôćĺ Server Frames ----
 15Ôćĺ
 16Ôćĺ/** Client requests data (one-shot). */
 17Ôćĺexport interface QRequestFrame {
 18Ôćĺ  type: "q:request";
 19Ôćĺ  id: string;
 20Ôćĺ  resource: QueryResource;
 21Ôćĺ  params?: Record<string, unknown>;
 22Ôćĺ}
 23Ôćĺ
 24Ôćĺ/** Client subscribes to live updates for a resource. */
 25Ôćĺexport interface QSubscribeFrame {
 26Ôćĺ  type: "q:subscribe";
 27Ôćĺ  id: string;
 28Ôćĺ  resource: QueryResource;
 29Ôćĺ  params?: Record<string, unknown>;
 30Ôćĺ}
 31Ôćĺ
 32Ôćĺ/** Client unsubscribes by subscription ID (no resource/params needed). */
 33Ôćĺexport interface QUnsubscribeFrame {
 34Ôćĺ  type: "q:unsubscribe";
 35Ôćĺ  id: string;
 36Ôćĺ}
 37Ôćĺ
 38Ôćĺ/** Client requests a mutation. Field is `action`, not `mutation`. */
 39Ôćĺexport interface QMutateFrame {
 40Ôćĺ  type: "q:mutate";
 41Ôćĺ  id: string;
 42Ôćĺ  action: MutationName;
 43Ôćĺ  params: Record<string, unknown>;
 44Ôćĺ}
 45Ôćĺ
 46Ôćĺ/** Client sends an async command (e.g. sendMessage, stopSession). */
 47Ôćĺexport interface QCommandFrame {
 48Ôćĺ  type: "q:command";
 49Ôćĺ  id: string;
 50Ôćĺ  command: CommandName;
 51Ôćĺ  params: Record<string, unknown>;
 52Ôćĺ}
 53Ôćĺ
 54Ôćĺ/** Client responds to a tool relay request (q:event tool:request Ôćĺ q:tool_response). */
 55Ôćĺexport interface QToolResponseSuccessFrame {
 56Ôćĺ  type: "q:tool_response";
 57Ôćĺ  requestId: string;
 58Ôćĺ  result: unknown;
 59Ôćĺ  error?: never;
 60Ôćĺ}
 61Ôćĺ
 62Ôćĺexport interface QToolResponseErrorFrame {
 63Ôćĺ  type: "q:tool_response";
 64Ôćĺ  requestId: string;
 65Ôćĺ  error: string;
 66Ôćĺ  result?: never;
 67Ôćĺ}
 68Ôćĺ
 69Ôćĺexport type QToolResponseFrame = QToolResponseSuccessFrame | QToolResponseErrorFrame;
 70Ôćĺ
 71Ôćĺ/** All frames a client can send. */
 72Ôćĺexport type QClientFrame =
 73Ôćĺ  | QRequestFrame
 74Ôćĺ  | QSubscribeFrame
 75Ôćĺ  | QUnsubscribeFrame
 76Ôćĺ  | QMutateFrame
 77Ôćĺ  | QCommandFrame
 78Ôćĺ  | QToolResponseFrame;
 79Ôćĺ
 80Ôćĺ// ---- Server Ôćĺ Client Frames ----
 81Ôćĺ
 82Ôćĺ/** Server returns data for a one-shot request. */
 83Ôćĺexport interface QResponseFrame {
 84Ôćĺ  type: "q:response";
 85Ôćĺ  id: string;
 86Ôćĺ  data: unknown;
 87Ôćĺ}
 88Ôćĺ
 89Ôćĺ/** Server pushes a full snapshot to a subscriber (keyed by subscription ID). */
 90Ôćĺexport interface QSnapshotFrame {
 91Ôćĺ  type: "q:snapshot";
 92Ôćĺ  id: string;
 93Ôćĺ  data: unknown;
 94Ôćĺ  cursor?: number;
