313Ôćĺ// ÔöÇÔöÇÔöÇ Manifest & Task Endpoints ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
314Ôćĺ
315Ôćĺ// Get parsed manifest + normalized tasks for a workspace
316Ôćĺapp.get("/workspaces/:id/manifest", withWorkspace, (c) => {
317Ôćĺ  const workspace = c.get("workspace");
318Ôćĺ  const workspacePath = c.get("workspacePath");
319Ôćĺ  if (!workspace.root_path) {
320Ôćĺ    return c.json({ manifest: null, tasks: [] });
321Ôćĺ  }
322Ôćĺ  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
323Ôćĺ  if (!manifest) return c.json({ manifest: null, tasks: [] });
324Ôćĺ  const tasks = getNormalizedTasks(manifest);
325Ôćĺ  return c.json({ manifest, tasks });
326Ôćĺ});
327Ôćĺ
328Ôćĺ// Retry failed setup
329Ôćĺapp.post("/workspaces/:id/retry-setup", withWorkspace, (c) => {
330Ôćĺ  const db = getDatabase();
331Ôćĺ  const workspace = c.get("workspace");
332Ôćĺ  const workspacePath = c.get("workspacePath");
333Ôćĺ
334Ôćĺ  if (workspace.setup_status !== "failed") {
335Ôćĺ    throw new ValidationError("Can only retry when setup_status is failed");
336Ôćĺ  }
337Ôćĺ
338Ôćĺ  if (!workspace.root_path) {
339Ôćĺ    throw new ValidationError("Repository path not found");
340Ôćĺ  }
341Ôćĺ
342Ôćĺ  // Re-read manifest (AI agent may have fixed it, or it was added to repo root via settings)
343Ôćĺ  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
344Ôćĺ  const setupCmd = manifest ? getSetupCommand(manifest) : null;
345Ôćĺ  if (!setupCmd || !manifest) {
346Ôćĺ    db.prepare(
