348Ôćĺ    ).run(workspace.id);
349Ôćĺ    return c.json({ setup_status: "none" });
350Ôćĺ  }
351Ôćĺ
352Ôćĺ  db.prepare(
353Ôćĺ    "UPDATE workspaces SET setup_status = 'running', error_message = NULL, updated_at = datetime('now') WHERE id = ?"
354Ôćĺ  ).run(workspace.id);
355Ôćĺ
356Ôćĺ  const setupEnv = getOpenDevsEnv(manifest, {
357Ôćĺ    id: workspace.id,
358Ôćĺ    rootPath: workspace.root_path,
359Ôćĺ    workspacePath,
360Ôćĺ  });
361Ôćĺ  runSetupScript(db, workspace.id, setupCmd, setupEnv, workspacePath);
362Ôćĺ
