370Ôćĺ  try {
371Ôćĺ    if (!fs.existsSync(setupLogPath)) return c.json({ logs: null });
372Ôćĺ    const logs = fs.readFileSync(setupLogPath, "utf8");
373Ôćĺ    return c.json({ logs });
374Ôćĺ  } catch {
375Ôćĺ    return c.json({ logs: null });
376Ôćĺ  }
377Ôćĺ});
378Ôćĺ
379Ôćĺ// Run a task ÔÇö validates task exists, returns info for frontend PTY spawn
380Ôćĺapp.post("/workspaces/:id/tasks/:name/run", withWorkspace, (c) => {
381Ôćĺ  const workspace = c.get("workspace");
382Ôćĺ  const workspacePath = c.get("workspacePath");
383Ôćĺ  const taskName = c.req.param("name");
384Ôćĺ
385Ôćĺ  if (!workspace.root_path) {
386Ôćĺ    throw new ValidationError("Repository path not found");
387Ôćĺ  }
388Ôćĺ
389Ôćĺ  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
390Ôćĺ  if (!manifest) throw new NotFoundError("No opendevs.json manifest found");
391Ôćĺ
392Ôćĺ  const tasks = getNormalizedTasks(manifest);
393Ôćĺ  const task = tasks.find((t) => t.name === taskName);
394Ôćĺ  if (!task) throw new NotFoundError(`Task "${taskName}" not found in manifest`);
395Ôćĺ
396Ôćĺ  const ptyId = `task-${workspace.id}-${taskName}-${Date.now()}`;
397Ôćĺ  const env = {
398Ôćĺ    ...(manifest.env ?? {}),
