  1Ôćĺ// backend/src/services/query-engine.ts
  2Ôćĺ// Query engine ÔÇö handles q:* protocol frames for typed reactive queries.
  3Ôćĺ// Module singleton: subscription state + dispatch logic.
  4Ôćĺ// Works for both local WS and relay-tunneled connections via WsSendable.
  5Ôćĺ//
  6Ôćĺ// Subscription model: ID-keyed. Client assigns IDs ("sub_1", "sub_2") and
  7Ôćĺ// server echoes them back on q:snapshot/q:delta so the client can route
  8Ôćĺ// to the correct callback.
  9Ôćĺ
 10Ôćĺimport { match } from "ts-pattern";
 11Ôćĺimport { getDatabase } from "../lib/database";
 12Ôćĺimport {
 13Ôćĺ  getDashboardWorkspaces,
 14Ôćĺ  getStats,
 15Ôćĺ  getSessionsByWorkspaceId,
 16Ôćĺ  getSessionById,
 17Ôćĺ  getMessages,
 18Ôćĺ  hasOlderMessages,
 19Ôćĺ  hasNewerMessages,
 20Ôćĺ  getWorkspaceRaw,
 21Ôćĺ  getMaxMessageSeq,
 22Ôćĺ  getMessagesDelta,
 23Ôćĺ  resetStatsCache,
 24Ôćĺ  getWorkspacesByRepo,
 25Ôćĺ  getWorkspacesBySessionIds,
 26Ôćĺ  getAllRepositorySummaries,
 27Ôćĺ} from "../db";
 28Ôćĺimport { computeWorkspacePath } from "../middleware/workspace-loader";
 29Ôćĺimport { getConnection } from "./ws.service";
 30Ôćĺimport { resolveToolRelay, rejectToolRelay, runCommand } from "./agent";
 31Ôćĺimport {
 32Ôćĺ  QUERY_RESOURCES,
 33Ôćĺ  MUTATION_NAMES,
 34Ôćĺ  COMMAND_NAMES,
 35Ôćĺ  type MutationName,
 36Ôćĺ  type CommandName,
 37Ôćĺ  type QueryResource,
 38Ôćĺ  type QServerFrame,
 39Ôćĺ} from "@shared/types/query-protocol";
 40Ôćĺ
 41Ôćĺ// ---- Subscription State ----
 42Ôćĺ
 43Ôćĺtype QueryParams = Record<string, unknown>;
 44Ôćĺ
 45Ôćĺinterface ResourceFrameInput {
 46Ôćĺ  id: string;
 47Ôćĺ  resource: string;
 48Ôćĺ  params: QueryParams;
 49Ôćĺ}
 50Ôćĺ
 51Ôćĺinterface UnsubscribeFrameInput {
 52Ôćĺ  id: string;
 53Ôćĺ}
 54Ôćĺ
 55Ôćĺinterface MutateFrameInput {
 56Ôćĺ  id: string;
 57Ôćĺ  action: string;
 58Ôćĺ  params: QueryParams;
 59Ôćĺ}
 60Ôćĺ
 61Ôćĺinterface CommandFrameInput {
 62Ôćĺ  id: string;
 63Ôćĺ  command: string;
 64Ôćĺ  params: QueryParams;
 65Ôćĺ}
 66Ôćĺ
 67Ôćĺinterface Sub {
 68Ôćĺ  id: string;
 69Ôćĺ  resource: QueryResource;
 70Ôćĺ  params: QueryParams;
 71Ôćĺ}
 72Ôćĺ
 73Ôćĺ/** Per-connection active subscriptions, keyed by client-assigned sub ID. */
 74Ôćĺconst subs = new Map<string, Map<string, Sub>>();
 75Ôćĺ
 76Ôćĺ/** For messages: track last seen seq per subscription for delta push.
 77Ôćĺ *  Key: `${connectionId}:${subId}` Ôćĺ lastSeq */
 78Ôćĺconst messageCursors = new Map<string, number>();
 79Ôćĺ
 80Ôćĺ// ---- Public API ----
 81Ôćĺ
 82Ôćĺ/**
 83Ôćĺ * Handle an incoming q:* frame from an authenticated connection.
 84Ôćĺ * Registered as onQueryFrame in ws.service protocol handlers.
 85Ôćĺ */
 86Ôćĺexport function handleFrame(connectionId: string, msg: QueryParams): void {
 87Ôćĺ  const type = typeof msg.type === "string" ? msg.type : "unknown";
 88Ôćĺ
 89Ôćĺ  try {
 90Ôćĺ    match(type)
 91Ôćĺ      .with("q:request", () => {
 92Ôćĺ        handleRequest(connectionId, parseResourceFrame(msg));
 93Ôćĺ      })
 94Ôćĺ      .with("q:subscribe", () => {
 95Ôćĺ        handleSubscribe(connectionId, parseResourceFrame(msg));
 96Ôćĺ      })
 97Ôćĺ      .with("q:unsubscribe", () => {
 98Ôćĺ        handleUnsubscribe(connectionId, parseUnsubscribeFrame(msg));
 99Ôćĺ      })
100Ôćĺ      .with("q:mutate", () => {
101Ôćĺ        handleMutate(connectionId, parseMutateFrame(msg));
102Ôćĺ      })
103Ôćĺ      .with("q:command", () => {
104Ôćĺ        handleCommand(connectionId, parseCommandFrame(msg));
105Ôćĺ      })
106Ôćĺ      .with("q:tool_response", () => {
107Ôćĺ        handleToolResponse(msg);
108Ôćĺ      })
109Ôćĺ      .otherwise(() => {
110Ôćĺ        sendFrame(connectionId, {
111Ôćĺ          type: "q:error",
112Ôćĺ          id: getFrameId(msg),
113Ôćĺ          code: "UNKNOWN_FRAME",
114Ôćĺ          message: `Unknown query frame type: ${type}`,
115Ôćĺ        });
116Ôćĺ      });
117Ôćĺ  } catch (err) {
118Ôćĺ    sendFrame(connectionId, {
119Ôćĺ      type: "q:error",
120Ôćĺ      id: getFrameId(msg),
121Ôćĺ      code: "INVALID_FRAME",
122Ôćĺ      message: err instanceof Error ? err.message : "Invalid query frame",
123Ôćĺ    });
124Ôćĺ  }
125Ôćĺ}
126Ôćĺ
127Ôćĺ/** Remove all subscriptions for a connection (cleanup on disconnect). */
128Ôćĺexport function removeSubs(connectionId: string): void {
129Ôćĺ  const connSubs = subs.get(connectionId);
130Ôćĺ  if (connSubs) {
131Ôćĺ    for (const [subId, sub] of connSubs) {
132Ôćĺ      if (sub.resource === "messages") {
133Ôćĺ        messageCursors.delete(`${connectionId}:${subId}`);
134Ôćĺ      }
135Ôćĺ    }
136Ôćĺ    subs.delete(connectionId);
137Ôćĺ  }
138Ôćĺ}
139Ôćĺ
140Ôćĺ/** Optional context for targeted invalidation (e.g., which sessions changed). */
141Ôćĺinterface InvalidateContext {
142Ôćĺ  sessionIds?: string[];
143Ôćĺ}
144Ôćĺ
145Ôćĺ/**
146Ôćĺ * Push-first invalidation: re-run queries for active subscribers and push
147Ôćĺ * fresh snapshots or deltas.
148Ôćĺ *
149Ôćĺ * Messages use q:delta (cursor-based) instead of full snapshots.
150Ôćĺ * When `ctx.sessionIds` is provided, workspace subscribers receive a targeted
151Ôćĺ * q:delta (only the changed workspaces) instead of a full q:snapshot.
152Ôćĺ */
153Ôćĺexport function invalidate(resources: QueryResource[], ctx?: InvalidateContext): void {
154Ôćĺ  if (resources.includes("stats")) {
155Ôćĺ    resetStatsCache();
156Ôćĺ  }
157Ôćĺ
158Ôćĺ  // Phase 1: Push fresh data to active subscribers
159Ôćĺ  for (const [connectionId, connSubs] of subs) {
160Ôćĺ    if (!getConnection(connectionId)) {
161Ôćĺ      removeSubs(connectionId);
162Ôćĺ      continue;
163Ôćĺ    }
164Ôćĺ
165Ôćĺ    for (const [subId, sub] of connSubs) {
166Ôćĺ      if (!resources.includes(sub.resource)) continue;
167Ôćĺ
168Ôćĺ      if (sub.resource === "messages") {
169Ôćĺ        // Messages: push delta (new messages since last cursor)
170Ôćĺ        pushMessageDelta(connectionId, subId, sub.params);
171Ôćĺ      } else if (sub.resource === "workspaces" && ctx?.sessionIds?.length) {
172Ôćĺ        // Workspaces with session context: try targeted delta
173Ôćĺ        try {
174Ôćĺ          const db = getDatabase();
175Ôćĺ          const stateFilter = readStringParam(sub.params, "state") ?? "ready,initializing";
176Ôćĺ          const allowedStates = new Set(stateFilter.split(",").map((s) => s.trim()));
177Ôćĺ          const changedWorkspaces = getWorkspacesBySessionIds(db, ctx.sessionIds).filter((ws) =>
178Ôćĺ            allowedStates.has(ws.state)
179Ôćĺ          );
180Ôćĺ          if (changedWorkspaces.length > 0) {
181Ôćĺ            const withPaths = changedWorkspaces.map((ws) => ({
182Ôćĺ              ...ws,
183Ôćĺ              workspace_path: computeWorkspacePath(ws),
184Ôćĺ            }));
185Ôćĺ            sendFrame(connectionId, {
186Ôćĺ              type: "q:delta",
187Ôćĺ              id: subId,
188Ôćĺ              upserted: withPaths,
189Ôćĺ            });
190Ôćĺ          } else {
191Ôćĺ            // Session IDs didn't match any workspaces ÔÇö fall back to full snapshot
192Ôćĺ            const data = runQuery(sub.resource, sub.params);
193Ôćĺ            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
194Ôćĺ          }
195Ôćĺ        } catch (err) {
196Ôćĺ          // Delta lookup failed ÔÇö fall back to full snapshot
197Ôćĺ          console.error(`[QueryEngine] Workspace delta failed, falling back to snapshot:`, err);
198Ôćĺ          try {
199Ôćĺ            const data = runQuery(sub.resource, sub.params);
200Ôćĺ            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
201Ôćĺ          } catch (snapErr) {
202Ôćĺ            console.error(`[QueryEngine] Snapshot fallback also failed:`, snapErr);
203Ôćĺ          }
204Ôćĺ        }
205Ôćĺ      } else if (sub.resource === "session" && ctx?.sessionIds?.length) {
206Ôćĺ        // Session with context: only push if this subscription's session is in the changed set
207Ôćĺ        const subscribedSessionId = readStringParam(sub.params, "sessionId");
208Ôćĺ        if (subscribedSessionId && ctx.sessionIds.includes(subscribedSessionId)) {
209Ôćĺ          try {
210Ôćĺ            const data = runQuery(sub.resource, sub.params);
211Ôćĺ            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
212Ôćĺ          } catch (err) {
213Ôćĺ            console.error(`[QueryEngine] Session snapshot push failed:`, err);
214Ôćĺ          }
215Ôćĺ        }
216Ôćĺ        // If session not in changed set, skip the push
217Ôćĺ      } else {
218Ôćĺ        // Other resources: push full snapshot
219Ôćĺ        try {
220Ôćĺ          const data = runQuery(sub.resource, sub.params);
221Ôćĺ          sendFrame(connectionId, {
222Ôćĺ            type: "q:snapshot",
223Ôćĺ            id: subId,
224Ôćĺ            data,
225Ôćĺ          });
226Ôćĺ        } catch (err) {
227Ôćĺ          console.error(`[QueryEngine] Snapshot push failed for ${sub.resource}:`, err);
228Ôćĺ        }
229Ôćĺ      }
230Ôćĺ    }
231Ôćĺ  }
232Ôćĺ}
233Ôćĺ
234Ôćĺ// ---- Frame Handlers ----
235Ôćĺ
236Ôćĺfunction handleRequest(connectionId: string, msg: ResourceFrameInput): void {
237Ôćĺ  const { id, resource, params } = msg;
238Ôćĺ
239Ôćĺ  try {
240Ôćĺ    const typedResource = toQueryResource(resource);
241Ôćĺ    const data = runQuery(typedResource, params);
242Ôćĺ    sendFrame(connectionId, { type: "q:response", id, data });
243Ôćĺ  } catch (err) {
244Ôćĺ    sendFrame(connectionId, {
245Ôćĺ      type: "q:error",
246Ôćĺ      id,
247Ôćĺ      code: "QUERY_ERROR",
248Ôćĺ      message: err instanceof Error ? err.message : "Query failed",
249Ôćĺ    });
250Ôćĺ  }
251Ôćĺ}
252Ôćĺ
253Ôćĺfunction handleSubscribe(connectionId: string, msg: ResourceFrameInput): void {
254Ôćĺ  const { id, resource, params } = msg;
255Ôćĺ
256Ôćĺ  // Validate resource upfront ÔÇö fail fast before running query
257Ôćĺ  const typedResource = toQueryResource(resource);
258Ôćĺ
259Ôćĺ  // Send initial snapshot ÔÇö only register subscription if query succeeds
260Ôćĺ  // (avoids zombie subscriptions when runQuery throws on invalid params)
261Ôćĺ  try {
262Ôćĺ    const data = runQuery(typedResource, params);
263Ôćĺ
264Ôćĺ    // Get or create subscription map for this connection
265Ôćĺ    let connSubs = subs.get(connectionId);
266Ôćĺ    if (!connSubs) {
267Ôćĺ      connSubs = new Map();
268Ôćĺ      subs.set(connectionId, connSubs);
269Ôćĺ    }
270Ôćĺ
271Ôćĺ    // Store subscription by client-assigned ID (replaces if same ID reused on reconnect)
272Ôćĺ    connSubs.set(id, { id, resource: typedResource, params });
273Ôćĺ
274Ôćĺ    // For messages: initialize cursor to current max seq
275Ôćĺ    if (typedResource === "messages") {
276Ôćĺ      const sessionId = readStringParam(params, "sessionId");
277Ôćĺ      const cursorKey = `${connectionId}:${id}`;
278Ôćĺ      if (sessionId) {
279Ôćĺ        try {
280Ôćĺ          const db = getDatabase();
281Ôćĺ          messageCursors.set(cursorKey, getMaxMessageSeq(db, sessionId));
282Ôćĺ        } catch {
283Ôćĺ          messageCursors.set(cursorKey, 0);
284Ôćĺ        }
285Ôćĺ      }
286Ôćĺ    }
287Ôćĺ
288Ôćĺ    sendFrame(connectionId, { type: "q:snapshot", id, data });
289Ôćĺ  } catch (err) {
290Ôćĺ    sendFrame(connectionId, {
291Ôćĺ      type: "q:error",
292Ôćĺ      id,
293Ôćĺ      code: "SUBSCRIBE_ERROR",
294Ôćĺ      message: err instanceof Error ? err.message : "Subscribe failed",
295Ôćĺ    });
296Ôćĺ  }
297Ôćĺ}
298Ôćĺ
299Ôćĺfunction handleUnsubscribe(connectionId: string, msg: UnsubscribeFrameInput): void {
300Ôćĺ  const { id } = msg;
301Ôćĺ
302Ôćĺ  const connSubs = subs.get(connectionId);
303Ôćĺ  if (!connSubs) return;
304Ôćĺ
305Ôćĺ  const sub = connSubs.get(id);
306Ôćĺ  if (sub) {
307Ôćĺ    // Clean up message cursor
308Ôćĺ    if (sub.resource === "messages") {
309Ôćĺ      messageCursors.delete(`${connectionId}:${id}`);
310Ôćĺ    }
311Ôćĺ    connSubs.delete(id);
312Ôćĺ    if (connSubs.size === 0) subs.delete(connectionId);
313Ôćĺ  }
314Ôćĺ}
315Ôćĺ
316Ôćĺfunction handleMutate(connectionId: string, msg: MutateFrameInput): void {
317Ôćĺ  const { id, action, params } = msg;
318Ôćĺ
319Ôćĺ  try {
320Ôćĺ    const result = runMutation(action, params);
321Ôćĺ    sendFrame(connectionId, {
322Ôćĺ      type: "q:mutate_result",
323Ôćĺ      id,
324Ôćĺ      success: true,
325Ôćĺ      data: result,
326Ôćĺ    });
327Ôćĺ  } catch (err) {
328Ôćĺ    sendFrame(connectionId, {
329Ôćĺ      type: "q:mutate_result",
330Ôćĺ      id,
331Ôćĺ      success: false,
332Ôćĺ      error: err instanceof Error ? err.message : "Mutation failed",
333Ôćĺ    });
334Ôćĺ  }
335Ôćĺ}
336Ôćĺ
337Ôćĺasync function handleCommand(connectionId: string, msg: CommandFrameInput): Promise<void> {
338Ôćĺ  const { id, command, params } = msg;
339Ôćĺ
340Ôćĺ  try {
341Ôćĺ    const result = await runCommand(toCommandName(command), params);
342Ôćĺ    sendFrame(connectionId, {
343Ôćĺ      type: "q:command_ack",
344Ôćĺ      id,
345Ôćĺ      accepted: true,
346Ôćĺ      ...result,
347Ôćĺ    } satisfies QServerFrame);
348Ôćĺ  } catch (err) {
349Ôćĺ    sendFrame(connectionId, {
350Ôćĺ      type: "q:command_ack",
351Ôćĺ      id,
352Ôćĺ      accepted: false,
353Ôćĺ      error: err instanceof Error ? err.message : "Command failed",
354Ôćĺ    } satisfies QServerFrame);
355Ôćĺ  }
356Ôćĺ}
357Ôćĺ
358Ôćĺ// ---- Tool Response Handler ----
359Ôćĺ
360Ôćĺfunction handleToolResponse(msg: QueryParams): void {
361Ôćĺ  const requestId = typeof msg.requestId === "string" ? msg.requestId : undefined;
362Ôćĺ  if (!requestId) {
363Ôćĺ    console.error("[QueryEngine] q:tool_response missing requestId");
364Ôćĺ    return;
365Ôćĺ  }
366Ôćĺ
367Ôćĺ  if ("error" in msg && msg.error !== undefined) {
368Ôćĺ    const errorStr = typeof msg.error === "string" ? msg.error : JSON.stringify(msg.error);
369Ôćĺ    const resolved = rejectToolRelay(requestId, errorStr);
370Ôćĺ    if (!resolved) {
371Ôćĺ      console.warn(`[QueryEngine] q:tool_response for unknown requestId=${requestId} (error)`);
372Ôćĺ    }
373Ôćĺ  } else {
374Ôćĺ    const resolved = resolveToolRelay(requestId, msg.result);
375Ôćĺ    if (!resolved) {
376Ôćĺ      console.warn(`[QueryEngine] q:tool_response for unknown requestId=${requestId} (result)`);
377Ôćĺ    }
378Ôćĺ  }
379Ôćĺ}
380Ôćĺ
381Ôćĺ// ---- Query Dispatch ----
382Ôćĺ
383Ôćĺfunction runQuery(resource: QueryResource, params: QueryParams): unknown {
384Ôćĺ  const db = getDatabase();
385Ôćĺ
386Ôćĺ  return match(resource)
387Ôćĺ    .with("workspaces", () => {
388Ôćĺ      // Return RepoGroup[] shape matching GET /workspaces/by-repo
389Ôćĺ      const state = readStringParam(params, "state") ?? "ready,initializing";
390Ôćĺ      const workspaces = getWorkspacesByRepo(db, state);
391Ôćĺ
392Ôćĺ      const grouped: Record<
393Ôćĺ        string,
394Ôćĺ        { repo_id: string; repo_name: string; sort_order: number; workspaces: unknown[] }
395Ôćĺ      > = {};
396Ôćĺ      workspaces.forEach((workspace) => {
397Ôćĺ        const repoId = workspace.repository_id || "unknown";
398Ôćĺ        if (!grouped[repoId]) {
399Ôćĺ          grouped[repoId] = {
400Ôćĺ            repo_id: repoId,
401Ôćĺ            repo_name: workspace.repo_name || "Unknown",
402Ôćĺ            sort_order: workspace.repo_sort_order ?? 999,
403Ôćĺ            workspaces: [],
404Ôćĺ          };
405Ôćĺ        }
406Ôćĺ        grouped[repoId].workspaces.push({
407Ôćĺ          ...workspace,
408Ôćĺ          workspace_path: computeWorkspacePath(workspace),
409Ôćĺ        });
410Ôćĺ      });
411Ôćĺ
412Ôćĺ      // Backfill repos that have no matching workspaces (e.g. all archived)
413Ôćĺ      const allRepos = getAllRepositorySummaries(db);
414Ôćĺ      for (const repo of allRepos) {
415Ôćĺ        if (!grouped[repo.id]) {
416Ôćĺ          grouped[repo.id] = {
417Ôćĺ            repo_id: repo.id,
418Ôćĺ            repo_name: repo.name,
419Ôćĺ            sort_order: repo.sort_order ?? 999,
420Ôćĺ            workspaces: [],
421Ôćĺ          };
422Ôćĺ        }
423Ôćĺ      }
424Ôćĺ
425Ôćĺ      return Object.values(grouped).sort((a, b) => a.sort_order - b.sort_order);
426Ôćĺ    })
427Ôćĺ    .with("stats", () => getStats(db))
428Ôćĺ    .with("sessions", () => {
429Ôćĺ      const workspaceId = readStringParam(params, "workspaceId");
430Ôćĺ      if (!workspaceId) throw new Error("sessions requires workspaceId param");
431Ôćĺ      return getSessionsByWorkspaceId(db, workspaceId);
432Ôćĺ    })
433Ôćĺ    .with("session", () => {
434Ôćĺ      const sessionId = readStringParam(params, "sessionId");
435Ôćĺ      if (!sessionId) throw new Error("session requires sessionId param");
436Ôćĺ      return getSessionById(db, sessionId);
437Ôćĺ    })
438Ôćĺ    .with("messages", () => {
439Ôćĺ      const sessionId = readStringParam(params, "sessionId");
440Ôćĺ      if (!sessionId) throw new Error("messages requires sessionId param");
441Ôćĺ
442Ôćĺ      const rows = getMessages(db, sessionId, {
443Ôćĺ        limit: readNumberParam(params, "limit") ?? 50,
444Ôćĺ        before: readNumberParam(params, "before"),
445Ôćĺ        after: readNumberParam(params, "after"),
446Ôćĺ      });
447Ôćĺ
448Ôćĺ      const hasOlder = rows.length > 0 ? hasOlderMessages(db, sessionId, rows[0].seq) : false;
449Ôćĺ      const hasNewer =
450Ôćĺ        rows.length > 0 ? hasNewerMessages(db, sessionId, rows[rows.length - 1].seq) : false;
451Ôćĺ
452Ôćĺ      return { messages: rows, has_older: hasOlder, has_newer: hasNewer };
453Ôćĺ    })
454Ôćĺ    .exhaustive();
455Ôćĺ}
456Ôćĺ
457Ôćĺ// ---- Mutation Dispatch ----
458Ôćĺ
459Ôćĺfunction runMutation(action: string, params: QueryParams): unknown {
460Ôćĺ  const typedAction = toMutationName(action);
461Ôćĺ
462Ôćĺ  return match(typedAction)
463Ôćĺ    .with("archiveWorkspace", () => {
464Ôćĺ      const db = getDatabase();
465Ôćĺ      const workspaceId = readStringParam(params, "workspaceId");
466Ôćĺ      if (!workspaceId) throw new Error("archiveWorkspace requires workspaceId");
467Ôćĺ
468Ôćĺ      const workspace = getWorkspaceRaw(db, workspaceId);
469Ôćĺ      if (!workspace) throw new Error("Workspace not found");
470Ôćĺ
471Ôćĺ      db.prepare("UPDATE workspaces SET state = 'archived' WHERE id = ?").run(workspaceId);
472Ôćĺ      invalidate(["workspaces", "stats"]);
473Ôćĺ      return { success: true };
474Ôćĺ    })
475Ôćĺ    .with("updateWorkspaceTitle", () => {
476Ôćĺ      const db = getDatabase();
477Ôćĺ      const workspaceId = readStringParam(params, "workspaceId");
478Ôćĺ      const title = readStringParam(params, "title");
479Ôćĺ      if (!workspaceId || title === undefined) {
480Ôćĺ        throw new Error("updateWorkspaceTitle requires workspaceId and title");
481Ôćĺ      }
482Ôćĺ
483Ôćĺ      const workspace = getWorkspaceRaw(db, workspaceId);
484Ôćĺ      if (!workspace) throw new Error("Workspace not found");
485Ôćĺ
486Ôćĺ      db.prepare("UPDATE workspaces SET title = ? WHERE id = ?").run(title, workspaceId);
487Ôćĺ      invalidate(["workspaces"]);
488Ôćĺ      return { success: true };
489Ôćĺ    })
490Ôćĺ    .exhaustive();
491Ôćĺ}
492Ôćĺ
493Ôćĺ// ---- Message Delta Push ----
494Ôćĺ
495Ôćĺfunction pushMessageDelta(connectionId: string, subId: string, params: QueryParams): void {
496Ôćĺ  const sessionId = readStringParam(params, "sessionId");
497Ôćĺ  if (!sessionId) return;
498Ôćĺ
499Ôćĺ  const cursorKey = `${connectionId}:${subId}`;
500Ôćĺ  const lastSeq = messageCursors.get(cursorKey) ?? 0;
501Ôćĺ
502Ôćĺ  try {
503Ôćĺ    const db = getDatabase();
504Ôćĺ    const newMessages = getMessagesDelta(db, sessionId, lastSeq);
505Ôćĺ
506Ôćĺ    if (newMessages.length === 0) return;
507Ôćĺ
508Ôćĺ    const maxSeq = newMessages[newMessages.length - 1].seq;
509Ôćĺ    messageCursors.set(cursorKey, maxSeq);
510Ôćĺ
511Ôćĺ    sendFrame(connectionId, {
512Ôćĺ      type: "q:delta",
513Ôćĺ      id: subId,
514Ôćĺ      upserted: newMessages,
515Ôćĺ      cursor: maxSeq,
516Ôćĺ    });
517Ôćĺ  } catch (err) {
518Ôćĺ    console.error(`[QueryEngine] Message delta push failed:`, err);
519Ôćĺ  }
520Ôćĺ}
521Ôćĺ
522Ôćĺ// ---- Helpers ----
523Ôćĺ
524Ôćĺfunction sendFrame(connectionId: string, frame: QServerFrame): void {
525Ôćĺ  const conn = getConnection(connectionId);
526Ôćĺ  if (!conn) return;
527Ôćĺ  try {
528Ôćĺ    conn.ws.send(JSON.stringify(frame));
529Ôćĺ  } catch {
530Ôćĺ    // Connection may have closed
531Ôćĺ  }
532Ôćĺ}
533Ôćĺ
534Ôćĺfunction parseResourceFrame(msg: QueryParams): ResourceFrameInput {
535Ôćĺ  return {
536Ôćĺ    id: requireString(msg.id, "id"),
537Ôćĺ    resource: requireString(msg.resource, "resource"),
538Ôćĺ    params: getParams(msg.params),
539Ôćĺ  };
540Ôćĺ}
541Ôćĺ
542Ôćĺfunction parseUnsubscribeFrame(msg: QueryParams): UnsubscribeFrameInput {
543Ôćĺ  return {
544Ôćĺ    id: requireString(msg.id, "id"),
545Ôćĺ  };
546Ôćĺ}
547Ôćĺ
548Ôćĺfunction parseMutateFrame(msg: QueryParams): MutateFrameInput {
549Ôćĺ  return {
550Ôćĺ    id: requireString(msg.id, "id"),
551Ôćĺ    action: requireString(msg.action, "action"),
552Ôćĺ    params: getParams(msg.params),
553Ôćĺ  };
554Ôćĺ}
555Ôćĺ
556Ôćĺfunction getParams(value: unknown): QueryParams {
557Ôćĺ  if (value == null) return {};
558Ôćĺ  if (isRecord(value)) return value;
559Ôćĺ  throw new Error("Frame params must be an object");
560Ôćĺ}
561Ôćĺ
562Ôćĺfunction requireString(value: unknown, field: string): string {
563Ôćĺ  if (typeof value !== "string") {
564Ôćĺ    throw new Error(`Frame requires string ${field}`);
565Ôćĺ  }
566Ôćĺ  return value;
567Ôćĺ}
568Ôćĺ
569Ôćĺfunction getFrameId(msg: QueryParams): string {
570Ôćĺ  return typeof msg.id === "string" ? msg.id : "unknown";
571Ôćĺ}
572Ôćĺ
573Ôćĺfunction isRecord(value: unknown): value is QueryParams {
574Ôćĺ  return typeof value === "object" && value !== null && !Array.isArray(value);
575Ôćĺ}
576Ôćĺ
577Ôćĺfunction readStringParam(params: QueryParams, key: string): string | undefined {
578Ôćĺ  const value = params[key];
579Ôćĺ  return typeof value === "string" ? value : undefined;
580Ôćĺ}
581Ôćĺ
582Ôćĺfunction readNumberParam(params: QueryParams, key: string): number | undefined {
583Ôćĺ  const value = params[key];
584Ôćĺ  return typeof value === "number" ? value : undefined;
585Ôćĺ}
586Ôćĺ
587Ôćĺfunction isQueryResource(value: string): value is QueryResource {
588Ôćĺ  return (QUERY_RESOURCES as readonly string[]).includes(value);
589Ôćĺ}
590Ôćĺ
591Ôćĺfunction toQueryResource(value: string): QueryResource {
592Ôćĺ  if (!isQueryResource(value)) throw new Error(`Unknown resource: ${value}`);
593Ôćĺ  return value;
594Ôćĺ}
595Ôćĺ
596Ôćĺfunction isMutationName(value: string): value is MutationName {
597Ôćĺ  return (MUTATION_NAMES as readonly string[]).includes(value);
598Ôćĺ}
599Ôćĺ
600Ôćĺfunction toMutationName(value: string): MutationName {
601Ôćĺ  if (!isMutationName(value)) throw new Error(`Unknown mutation: ${value}`);
602Ôćĺ  return value;
603Ôćĺ}
604Ôćĺ
605Ôćĺfunction parseCommandFrame(msg: QueryParams): CommandFrameInput {
606Ôćĺ  return {
607Ôćĺ    id: requireString(msg.id, "id"),
608Ôćĺ    command: requireString(msg.command, "command"),
609Ôćĺ    params: getParams(msg.params),
610Ôćĺ  };
611Ôćĺ}
612Ôćĺ
613Ôćĺfunction isCommandName(value: string): value is CommandName {
614Ôćĺ  return (COMMAND_NAMES as readonly string[]).includes(value);
615Ôćĺ}
616Ôćĺ
617Ôćĺfunction toCommandName(value: string): CommandName {
618Ôćĺ  if (!isCommandName(value)) throw new Error(`Unknown command: ${value}`);
619Ôćĺ  return value;
620Ôćĺ}
621Ôćĺ

