  1Ôćĺ/**
  2Ôćĺ * Workspace Query Hooks
  3Ôćĺ * TanStack Query hooks for workspace-related data fetching
  4Ôćĺ */
  5Ôćĺ
  6Ôćĺimport { useQuery, useMutation, useQueryClient, keepPreviousData } from "@tanstack/react-query";
  7Ôćĺimport { useMemo } from "react";
  8Ôćĺimport { produce } from "immer";
  9Ôćĺimport { WorkspaceService } from "./workspace.service";
 10Ôćĺimport { RepoService } from "@/features/repository/api/repository.service";
 11Ôćĺimport { queryKeys } from "@/shared/api/queryKeys";
 12Ôćĺimport { useQuerySubscription } from "@/shared/hooks/useQuerySubscription";
 13Ôćĺimport type { RepoGroup, DiffStats } from "../types";
 14Ôćĺimport type { PRStatus } from "@/shared/types";
 15Ôćĺimport { createOptimisticWorkspace, mergeWorkspaceDelta } from "../lib/workspace.utils";
 16Ôćĺimport { track } from "@/platform/analytics";
 17Ôćĺ
 18Ôćĺ/**
 19Ôćĺ * Fetch workspaces grouped by repository.
 20Ôćĺ *
 21Ôćĺ * WS subscription pushes data directly into cache via q:snapshot.
 22Ôćĺ * HTTP queryFn is fallback for initial load before WS connects.
 23Ôćĺ * Event-driven invalidation via IPC events also works (both paths coexist).
 24Ôćĺ */
 25Ôćĺexport function useWorkspacesByRepo(state: string = "ready,initializing") {
 26Ôćĺ  useQuerySubscription("workspaces", {
 27Ôćĺ    queryKey: queryKeys.workspaces.byRepo(state),
 28Ôćĺ    params: { state },
 29Ôćĺ    mergeDelta: mergeWorkspaceDelta,
 30Ôćĺ  });
 31Ôćĺ
 32Ôćĺ  return useQuery({
 33Ôćĺ    queryKey: queryKeys.workspaces.byRepo(state),
 34Ôćĺ    queryFn: () => WorkspaceService.fetchByRepo(state),
 35Ôćĺ    staleTime: Infinity, // WS subscription keeps data fresh
 36Ôćĺ    refetchOnWindowFocus: false, // Subscription handles freshness
 37Ôćĺ  });
 38Ôćĺ}
 39Ôćĺ
 40Ôćĺ/**
 41Ôćĺ * Fetch global stats.
 42Ôćĺ *
 43Ôćĺ * WS subscription pushes data directly into cache via q:snapshot.
 44Ôćĺ * HTTP queryFn is fallback for initial load before WS connects.
 45Ôćĺ */
 46Ôćĺexport function useStats() {
 47Ôćĺ  useQuerySubscription("stats", {
 48Ôćĺ    queryKey: queryKeys.stats.all,
 49Ôćĺ  });
 50Ôćĺ
 51Ôćĺ  return useQuery({
 52Ôćĺ    queryKey: queryKeys.stats.all,
 53Ôćĺ    queryFn: () => RepoService.fetchStats(),
 54Ôćĺ    staleTime: Infinity, // WS subscription keeps data fresh
 55Ôćĺ    refetchOnWindowFocus: false, // Subscription handles freshness
 56Ôćĺ  });
 57Ôćĺ}
 58Ôćĺ
 59Ôćĺ/**
 60Ôćĺ * Fetch diff stats for a specific workspace
 61Ôćĺ * Conditionally polls only when workspace is actively working.
 62Ôćĺ *
 63Ôćĺ * When `isWatched` is true (file watcher active via notify crate),
 64Ôćĺ * polling is disabled ÔÇö cache invalidation comes from fs:changed events.
 65Ôćĺ * Falls back to 5s polling when not watched.
 66Ôćĺ *
 67Ôćĺ * IMPORTANT: Requires workspaceState === "ready" to avoid fetching diffs
 68Ôćĺ * against incomplete worktrees during initialization. Running git diff on
 69Ôćĺ * an initializing worktree produces garbage (e.g. +500K/-1M) that gets
 70Ôćĺ * cached for 30s, persisting as phantom diffs even after the workspace
 71Ôćĺ * becomes ready. Guard here, not in the UI.
 72Ôćĺ */
 73Ôćĺexport function useDiffStats(
 74Ôćĺ  workspaceId: string | null,
 75Ôćĺ  sessionStatus?: string | null,
 76Ôćĺ  isWatched: boolean = false,
 77Ôćĺ  workspaceState?: string | null
 78Ôćĺ) {
 79Ôćĺ  return useQuery({
 80Ôćĺ    queryKey: queryKeys.workspaces.diffStats(workspaceId || ""),
 81Ôćĺ    queryFn: () => WorkspaceService.fetchDiffStats(workspaceId!),
 82Ôćĺ    enabled: !!workspaceId && workspaceState === "ready",
 83Ôćĺ    staleTime: 30000,
 84Ôćĺ    // Events handle invalidation when watched; fall back to polling otherwise
 85Ôćĺ    refetchInterval: isWatched ? false : sessionStatus === "working" ? 5000 : false,
 86Ôćĺ    refetchOnMount: "always",
 87Ôćĺ    refetchOnWindowFocus: true,
 88Ôćĺ  });
 89Ôćĺ}
 90Ôćĺ
 91Ôćĺ/**
 92Ôćĺ * Fetch diff stats for all sidebar workspaces in bulk.
 93Ôćĺ *
 94Ôćĺ * Replaces per-item useDiffStats() in the sidebar (N hooks Ôćĺ 1 query).
 95Ôćĺ * - Initial load: fetches ALL ready workspaces in parallel batches of 15
 96Ôćĺ * - Polling: only re-fetches workspaces with session_status === "working" (5s)
 97Ôćĺ * - Idle: no polling (staleTime 30s, refetch on window focus)
 98Ôćĺ * - On workspace list change: seeds from per-workspace cache, fetches only missing/working
 99Ôćĺ *
100Ôćĺ * Guard: state === "ready" ÔÇö initializing worktrees have incomplete git state
101Ôćĺ * (missing HEAD, partial index Ôćĺ garbage diffs like +500K/-1M). Setup script
102Ôćĺ * diffs are fine ÔÇö .gitignore handles them, and `git checkout -- .` in the
103Ôćĺ * init pipeline resets any tracked-file mutations from bun install.
104Ôćĺ */
105Ôćĺexport function useBulkDiffStats(repoGroups: RepoGroup[]) {
106Ôćĺ  const queryClient = useQueryClient();
107Ôćĺ
108Ôćĺ  // Stable, de-duplicated IDs for query key ÔÇö only ready workspaces.
109Ôćĺ  const workspaceIds = useMemo(() => {
110Ôćĺ    const ids = repoGroups.flatMap((g) =>
111Ôćĺ      g.workspaces.filter((w) => w.state === "ready").map((w) => w.id)
112Ôćĺ    );
113Ôćĺ    return Array.from(new Set(ids)).sort();
114Ôćĺ  }, [repoGroups]);
115Ôćĺ
116Ôćĺ  // IDs of workspaces with active sessions ÔÇö only these need polling.
117Ôćĺ  const workingIds = useMemo(() => {
118Ôćĺ    return repoGroups
119Ôćĺ      .flatMap((g) => g.workspaces)
120Ôćĺ      .filter((w) => w.state === "ready" && w.session_status === "working")
121Ôćĺ      .map((w) => w.id);
122Ôćĺ  }, [repoGroups]);
123Ôćĺ
124Ôćĺ  const hasWorkingWorkspaces = workingIds.length > 0;
125Ôćĺ
126Ôćĺ  return useQuery({
127Ôćĺ    queryKey: ["bulk-diff-stats", workspaceIds],
128Ôćĺ    enabled: workspaceIds.length > 0,
129Ôćĺ    staleTime: 30_000,
130Ôćĺ    placeholderData: keepPreviousData,
131Ôćĺ    refetchInterval: hasWorkingWorkspaces ? 5000 : false,
132Ôćĺ    refetchOnMount: "always",
133Ôćĺ    refetchOnWindowFocus: true,
134Ôćĺ    queryFn: async () => {
135Ôćĺ      // Seed from per-workspace cache for workspaces we already have data for
136Ôćĺ      const results: Record<string, DiffStats> = {};
137Ôćĺ      for (const id of workspaceIds) {
138Ôćĺ        const cached = queryClient.getQueryData<DiffStats>(queryKeys.workspaces.diffStats(id));
139Ôćĺ        if (cached) results[id] = cached;
140Ôćĺ      }
141Ôćĺ
142Ôćĺ      // Fetch: missing workspaces + working workspaces (need fresh data)
143Ôćĺ      const missingIds = workspaceIds.filter((id) => !(id in results));
144Ôćĺ      const idsToFetch = [...new Set([...missingIds, ...workingIds])];
145Ôćĺ
146Ôćĺ      if (idsToFetch.length === 0) return results;
147Ôćĺ
148Ôćĺ      // Parallel batches of 15 ÔÇö balances throughput vs resource pressure
149Ôćĺ      const BATCH_SIZE = 15;
150Ôćĺ      for (let i = 0; i < idsToFetch.length; i += BATCH_SIZE) {
151Ôćĺ        const batch = idsToFetch.slice(i, i + BATCH_SIZE);
152Ôćĺ        const settled = await Promise.allSettled(
153Ôćĺ          batch.map((id) => WorkspaceService.fetchDiffStats(id))
154Ôćĺ        );
155Ôćĺ
156Ôćĺ        batch.forEach((id, j) => {
157Ôćĺ          if (settled[j].status === "fulfilled") {
158Ôćĺ            results[id] = settled[j].value;
159Ôćĺ            queryClient.setQueryData(queryKeys.workspaces.diffStats(id), settled[j].value);
160Ôćĺ          }
161Ôćĺ        });
162Ôćĺ      }
163Ôćĺ
164Ôćĺ      return results;
165Ôćĺ    },
166Ôćĺ  });
167Ôćĺ}
168Ôćĺ
169Ôćĺ/**
170Ôćĺ * Fetch file changes for a workspace
171Ôćĺ * Conditionally polls only when workspace is actively working.
172Ôćĺ *
173Ôćĺ * When `isWatched` is true (file watcher active via notify crate),
174Ôćĺ * polling is disabled ÔÇö cache invalidation comes from fs:changed events.
175Ôćĺ * Falls back to 5s polling when not watched.
176Ôćĺ *
177Ôćĺ * IMPORTANT: Requires workspaceState === "ready" ÔÇö same guard as useDiffStats.
178Ôćĺ * See useDiffStats comment for the full explanation of the phantom diff race.
179Ôćĺ */
180Ôćĺexport function useFileChanges(
181Ôćĺ  workspaceId: string | null,
