183Ôćĺ  isWatched: boolean = false,
184Ôćĺ  workspaceState?: string | null
185Ôćĺ) {
186Ôćĺ  return useQuery({
187Ôćĺ    queryKey: queryKeys.workspaces.diffFiles(workspaceId || ""),
188Ôćĺ    queryFn: async () => {
