194Ôćĺ      };
195Ôćĺ    },
196Ôćĺ    enabled: !!workspaceId && workspaceState === "ready",
197Ôćĺ    staleTime: 30000,
198Ôćĺ    // Events handle invalidation when watched; fall back to polling otherwise
199Ôćĺ    refetchInterval: isWatched ? false : sessionStatus === "working" ? 5000 : false,
200Ôćĺ    refetchOnMount: "always",
201Ôćĺ    refetchOnWindowFocus: true,
202Ôćĺ  });
203Ôćĺ}
