309Ôćĺ/**
310Ôćĺ * Create workspace mutation with optimistic update.
311Ôćĺ *
312Ôćĺ * Flow:
313Ôćĺ * 1. User clicks "+" Ôćĺ placeholder workspace appears instantly in sidebar
314Ôćĺ * 2. Backend creates workspace (state = "initializing"), returns it
315Ôćĺ * 3. onSuccess replaces placeholder with real data, triggers refetch
316Ôćĺ * 4. Workspace progress events + terminal invalidation catch the ready transition
317Ôćĺ */
318Ôćĺexport function useCreateWorkspace() {
319Ôćĺ  const queryClient = useQueryClient();
320Ôćĺ  const queryKey = queryKeys.workspaces.byRepo("ready,initializing");
321Ôćĺ
322Ôćĺ  return useMutation({
323Ôćĺ    mutationFn: (repositoryId: string) => WorkspaceService.create(repositoryId),
324Ôćĺ
325Ôćĺ    onMutate: async (repositoryId: string) => {
326Ôćĺ      await queryClient.cancelQueries({ queryKey });
327Ôćĺ
328Ôćĺ      const previousData = queryClient.getQueryData<RepoGroup[]>(queryKey);
329Ôćĺ
330Ôćĺ      // Inject a placeholder workspace into the matching repo group
331Ôćĺ      queryClient.setQueryData<RepoGroup[]>(queryKey, (old) => {
332Ôćĺ        if (!old) return old;
333Ôćĺ        return produce(old, (draft) => {
334Ôćĺ          const repoGroup = draft.find((g) => g.repo_id === repositoryId);
335Ôćĺ          if (repoGroup) {
336Ôćĺ            repoGroup.workspaces.unshift(
337Ôćĺ              createOptimisticWorkspace(repositoryId, repoGroup.repo_name)
338Ôćĺ            );
339Ôćĺ          }
340Ôćĺ        });
341Ôćĺ      });
342Ôćĺ
343Ôćĺ      return { previousData };
344Ôćĺ    },
345Ôćĺ
346Ôćĺ    onError: (_err, _repositoryId, context) => {
347Ôćĺ      if (context?.previousData) {
348Ôćĺ        queryClient.setQueryData(queryKey, context.previousData);
349Ôćĺ      }
350Ôćĺ    },
351Ôćĺ
352Ôćĺ    onSuccess: (_data, repositoryId) => {
353Ôćĺ      track("workspace_created", { repository_id: repositoryId });
354Ôćĺ    },
355Ôćĺ
356Ôćĺ    onSettled: () => {
357Ôćĺ      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
358Ôćĺ    },
359Ôćĺ  });
360Ôćĺ}
