372Ôćĺ    },
373Ôćĺ    enabled: !!_workspacePath,
374Ôćĺ    staleTime: 30_000,
375Ôćĺ  });
376Ôćĺ}
377Ôćĺ
378Ôćĺ/**
379Ôćĺ * Archive workspace mutation with optimistic update
380Ôćĺ *
381Ôćĺ * Flow:
382Ôćĺ * 1. User clicks archive Ôćĺ UI updates IMMEDIATELY (workspace removed from list)
383Ôćĺ * 2. HTTP request sent in background
384Ôćĺ * 3. Success: Cache already correct, refetch confirms
385Ôćĺ * 4. Error: Rollback to previous state, show error
386Ôćĺ */
387Ôćĺexport function useArchiveWorkspace() {
388Ôćĺ  const queryClient = useQueryClient();
389Ôćĺ  const queryKey = queryKeys.workspaces.byRepo("ready,initializing");
390Ôćĺ
391Ôćĺ  return useMutation({
392Ôćĺ    mutationFn: (workspaceId: string) => WorkspaceService.archive(workspaceId),
393Ôćĺ
394Ôćĺ    // Optimistic update: Remove workspace from UI immediately
395Ôćĺ    onMutate: async (workspaceId: string) => {
396Ôćĺ      // Cancel any outgoing refetches (so they don't overwrite our optimistic update)
397Ôćĺ      await queryClient.cancelQueries({ queryKey });
398Ôćĺ
399Ôćĺ      // Snapshot the previous value
400Ôćĺ      const previousData = queryClient.getQueryData<RepoGroup[]>(queryKey);
401Ôćĺ
402Ôćĺ      // Optimistically remove the workspace from the list
403Ôćĺ      queryClient.setQueryData<RepoGroup[]>(queryKey, (old) => {
404Ôćĺ        if (!old) return old;
405Ôćĺ        return produce(old, (draft) => {
406Ôćĺ          for (const repo of draft) {
407Ôćĺ            const index = repo.workspaces.findIndex((w) => w.id === workspaceId);
408Ôćĺ            if (index !== -1) {
409Ôćĺ              repo.workspaces.splice(index, 1);
410Ôćĺ              break;
411Ôćĺ            }
412Ôćĺ          }
413Ôćĺ        });
414Ôćĺ      });
415Ôćĺ
416Ôćĺ      // Return context with the previous value for rollback
417Ôćĺ      return { previousData };
418Ôćĺ    },
419Ôćĺ
420Ôćĺ    // If mutation fails, roll back to the previous value
421Ôćĺ    onError: (_err, _workspaceId, context) => {
422Ôćĺ      if (context?.previousData) {
423Ôćĺ        queryClient.setQueryData(queryKey, context.previousData);
424Ôćĺ      }
425Ôćĺ    },
426Ôćĺ
427Ôćĺ    onSuccess: (_data, workspaceId) => {
428Ôćĺ      track("workspace_archived", { workspace_id: workspaceId });
429Ôćĺ    },
430Ôćĺ
431Ôćĺ    // Always refetch after error or success to ensure consistency
432Ôćĺ    onSettled: () => {
433Ôćĺ      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
434Ôćĺ    },
435Ôćĺ  });
436Ôćĺ}
437Ôćĺ
438Ôćĺ/**
