444Ôćĺ
445Ôćĺ  return useMutation({
446Ôćĺ    mutationFn: (workspaceId: string) => WorkspaceService.update(workspaceId, { state: "ready" }),
447Ôćĺ    onSuccess: (_data, workspaceId) => {
448Ôćĺ      track("workspace_unarchived", { workspace_id: workspaceId });
449Ôćĺ    },
450Ôćĺ    onSettled: () => {
451Ôćĺ      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
452Ôćĺ    },
453Ôćĺ  });
454Ôćĺ}
455Ôćĺ
456Ôćĺ/**
457Ôćĺ * Fetch system prompt for a workspace
458Ôćĺ */
