485Ôćĺ      });
486Ôćĺ
487Ôćĺ      const previousPrompt = queryClient.getQueryData<string>(
488Ôćĺ        queryKeys.workspaces.systemPrompt(workspaceId)
489Ôćĺ      );
490Ôćĺ
491Ôćĺ      queryClient.setQueryData(queryKeys.workspaces.systemPrompt(workspaceId), systemPrompt);
492Ôćĺ
493Ôćĺ      return { previousPrompt };
494Ôćĺ    },
495Ôćĺ
496Ôćĺ    onError: (_err, variables, context) => {
497Ôćĺ      if (context?.previousPrompt !== undefined) {
498Ôćĺ        queryClient.setQueryData(
