500Ôćĺ          context.previousPrompt
501Ôćĺ        );
502Ôćĺ      }
503Ôćĺ    },
504Ôćĺ
505Ôćĺ    onSettled: (_, __, variables) => {
506Ôćĺ      queryClient.invalidateQueries({
