 26Ôćĺ}
 27Ôćĺ
 28Ôćĺ/**
 29Ôćĺ * Visual configuration for each status
 30Ôćĺ *
 31Ôćĺ * Design System:
 32Ôćĺ * - badge: Color for notification badges (collapsed sidebar)
 33Ôćĺ * - border: Border/glow color for active states
 34Ôćĺ * - text: Text color for status labels
 35Ôćĺ * - bg: Background color for sections/cards
 36Ôćĺ *
 37Ôćĺ * Color Semantics:
 38Ôćĺ * ­čö┤ Red (error) = Critical, blocking, needs immediate action
 39Ôćĺ * ­ččí Amber (unread) = Important, needs attention when ready
 40Ôćĺ * ­ččó Green (working) = Active, positive, making progress
 41Ôćĺ * ­ččú Purple (compacting) = Transient, maintenance, ignore
 42Ôćĺ * ÔÜ¬ Gray (idle) = Dormant, background, low priority
 43Ôćĺ */
 44Ôćĺexport interface StatusConfig {
 45Ôćĺ  priority: StatusPriority;
 46Ôćĺ  label: string;
 47Ôćĺ  labelActive: string; // Present continuous form (e.g., "Working...")
