 52Ôćĺ  pulse?: boolean; // Whether to animate/pulse
 53Ôćĺ}
 54Ôćĺ
 55Ôćĺ/**
 56Ôćĺ * Status configuration map
 57Ôćĺ *
 58Ôćĺ * IMPORTANT: To change colors, edit this object (no component changes needed)
 59Ôćĺ */
 60Ôćĺexport const STATUS_CONFIG: Record<DisplayStatus, StatusConfig> = {
 61Ôćĺ  error: {
 62Ôćĺ    priority: StatusPriority.ERROR,
 63Ôćĺ    label: "Error",
 64Ôćĺ    labelActive: "Error",
 65Ôćĺ    badge: "bg-destructive text-destructive-foreground",
 66Ôćĺ    border: "border-destructive/60",
 67Ôćĺ    text: "text-destructive",
 68Ôćĺ    bg: "bg-destructive/10",
 69Ôćĺ    pulse: true,
 70Ôćĺ  },
 71Ôćĺ  unread: {
 72Ôćĺ    priority: StatusPriority.UNREAD,
 73Ôćĺ    label: "Needs Response",
 74Ôćĺ    labelActive: "Awaiting Input",
 75Ôćĺ    badge: "bg-status-unread text-status-unread-fg",
 76Ôćĺ    border: "border-status-unread/60",
 77Ôćĺ    text: "text-status-unread",
 78Ôćĺ    bg: "bg-status-unread/10",
 79Ôćĺ    pulse: false,
 80Ôćĺ  },
 81Ôćĺ  working: {
 82Ôćĺ    priority: StatusPriority.WORKING,
 83Ôćĺ    label: "Working",
 84Ôćĺ    labelActive: "Working...",
 85Ôćĺ    badge: "bg-primary text-primary-foreground",
 86Ôćĺ    border: "border-primary/60",
 87Ôćĺ    text: "text-primary",
 88Ôćĺ    bg: "bg-primary/10",
 89Ôćĺ    pulse: true,
 90Ôćĺ  },
 91Ôćĺ  idle: {
 92Ôćĺ    priority: StatusPriority.IDLE,
 93Ôćĺ    label: "Idle",
 94Ôćĺ    labelActive: "Idle",
 95Ôćĺ    badge: "bg-muted text-muted-foreground",
 96Ôćĺ    border: "border-muted",
 97Ôćĺ    text: "text-muted-foreground",
 98Ôćĺ    bg: "bg-muted/30",
 99Ôćĺ    pulse: false,
100Ôćĺ  },
