102Ôćĺ
103Ôćĺ/**
104Ôćĺ * Derive display status from workspace data
105Ôćĺ *
106Ôćĺ * Priority logic:
107Ôćĺ * 1. Error ÔÇö session in error state
108Ôćĺ * 2. Unread ÔÇö agent needs user response (needs_response / needs_plan_response)
109Ôćĺ * 3. Working ÔÇö agent actively processing
110Ôćĺ * 4. Idle ÔÇö dormant
111Ôćĺ *
112Ôćĺ * @param workspace Workspace data with session info
113Ôćĺ * @returns Derived display status for UI rendering
114Ôćĺ */
115Ôćĺexport function getDisplayStatus(workspace: Workspace): DisplayStatus {
116Ôćĺ  const status = workspace.session_status;
117Ôćĺ
118Ôćĺ  if (status === "error") return "error";
119Ôćĺ  if (status === "needs_response" || status === "needs_plan_response") return "unread";
120Ôćĺ  if (status === "working") return "working";
121Ôćĺ  return "idle";
122Ôćĺ}
123Ôćĺ
124Ôćĺ/**
125Ôćĺ * Check if workspace needs user attention.
126Ôćĺ * In V2, attention state is derived from session_status (needs_response / needs_plan_response).
127Ôćĺ */
128Ôćĺexport function getUnreadCount(workspace: Workspace): number {
129Ôćĺ  const status = workspace.session_status;
130Ôćĺ  return status === "needs_response" || status === "needs_plan_response" ? 1 : 0;
131Ôćĺ}
132Ôćĺ
133Ôćĺ/**
134Ôćĺ * Sort workspaces by status priority
135Ôćĺ * Higher priority statuses appear first
136Ôćĺ *
137Ôćĺ * @param workspaces Array of workspaces to sort
138Ôćĺ * @returns Sorted array (original array not mutated)
139Ôćĺ */
140Ôćĺexport function sortByStatusPriority<T extends Workspace>(workspaces: T[]): T[] {
141Ôćĺ  return [...workspaces].sort((a, b) => {
142Ôćĺ    const statusA = getDisplayStatus(a);
143Ôćĺ    const statusB = getDisplayStatus(b);
144Ôćĺ    const priorityA = STATUS_CONFIG[statusA].priority;
145Ôćĺ    const priorityB = STATUS_CONFIG[statusB].priority;
146Ôćĺ
147Ôćĺ    // Higher priority first
148Ôćĺ    if (priorityA !== priorityB) {
149Ôćĺ      return priorityB - priorityA;
150Ôćĺ    }
151Ôćĺ
152Ôćĺ    // Same priority: sort by latest activity (most recent first)
153Ôćĺ    const timeA = new Date(a.updated_at).getTime();
154Ôćĺ    const timeB = new Date(b.updated_at).getTime();
155Ôćĺ    return timeB - timeA;
156Ôćĺ  });
157Ôćĺ}
158Ôćĺ
159Ôćĺ/**
160Ôćĺ * Group workspaces by display status
161Ôćĺ * Used for rendering section headers in expanded sidebar
162Ôćĺ *
163Ôćĺ * @param workspaces Array of workspaces to group
164Ôćĺ * @returns Object with status as keys, workspace arrays as values
165Ôćĺ */
166Ôćĺexport function groupByStatus<T extends Workspace>(
167Ôćĺ  workspaces: T[]
168Ôćĺ): Partial<Record<DisplayStatus, T[]>> {
169Ôćĺ  const groups: Partial<Record<DisplayStatus, T[]>> = {};
170Ôćĺ
171Ôćĺ  workspaces.forEach((workspace) => {
172Ôćĺ    const status = getDisplayStatus(workspace);
173Ôćĺ    if (!groups[status]) {
174Ôćĺ      groups[status] = [];
175Ôćĺ    }
176Ôćĺ    groups[status]!.push(workspace);
177Ôćĺ  });
178Ôćĺ
179Ôćĺ  return groups;
180Ôćĺ}
181Ôćĺ
182Ôćĺ/**
183Ôćĺ * Get aggregate status counts for a repository
184Ôćĺ * Used for collapsed sidebar status indicators
185Ôćĺ *
186Ôćĺ * @param workspaces Workspaces in a repository
187Ôćĺ * @returns Count of each status type
188Ôćĺ */
189Ôćĺexport function getStatusCounts(workspaces: Workspace[]): Record<DisplayStatus, number> {
190Ôćĺ  const counts: Record<DisplayStatus, number> = {
191Ôćĺ    error: 0,
192Ôćĺ    unread: 0,
193Ôćĺ    working: 0,
194Ôćĺ    idle: 0,
195Ôćĺ  };
196Ôćĺ
197Ôćĺ  workspaces.forEach((workspace) => {
198Ôćĺ    const status = getDisplayStatus(workspace);
199Ôćĺ    counts[status]++;
200Ôćĺ  });
201Ôćĺ
202Ôćĺ  return counts;
203Ôćĺ}
204Ôćĺ
205Ôćĺ/**
