/**
 * Database row types ÔÇö internal to the backend.
 *
 * These match the raw shapes returned by better-sqlite3 queries.
 * They are NOT the API contract (see shared/types/ for that).
 * The `as` casts live in queries.ts, not in route handlers.
 */

// ÔöÇÔöÇÔöÇ repositories ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export interface RepositoryRow {
  id: string;
  name: string;
  root_path: string;
  git_default_branch: string;
  sort_order: number;
  git_origin_url: string | null;
  updated_at: string;
}

/** GET /repos ÔÇö repositories with workspace counts from LEFT JOIN aggregate. */
export interface RepositoryWithCountsRow extends RepositoryRow {
  ready_count: number;
  archived_count: number;
  total_count: number;
}

// ÔöÇÔöÇÔöÇ workspaces ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export interface WorkspaceRow {
  id: string;
  repository_id: string;
  slug: string;
  title: string | null;
  git_branch: string | null;
  git_target_branch: string | null;
  state: string;
  status: string;
  current_session_id: string | null;
  pr_url: string | null;
  pr_number: number | null;
  archive_commit: string | null;
  archived_at: string | null;
  setup_status: string;
  init_stage: string | null;
  error_message: string | null;
  updated_at: string;
}

/**
 * Workspace joined with repo + active session.
 * Used by GET /workspaces, GET /workspaces/:id, GET /workspaces/by-repo,
 * and the withWorkspace middleware.
 */
export interface WorkspaceWithDetailsRow {
  // From workspaces table
  id: string;
  repository_id: string;
  slug: string;
  title: string | null;
  git_branch: string | null;
  git_target_branch: string | null;
  state: string;
  status: string;
  current_session_id: string | null;
  pr_url: string | null;
  pr_number: number | null;
  init_stage: string | null;
  updated_at: string;

  // Setup tracking (opendevs.json manifest)
  setup_status: string;
  error_message: string | null;

  // From repositories JOIN
  repo_name: string | null;
  root_path: string | null;
  git_default_branch: string | null;
  /** Only in by-repo query */
  repo_sort_order?: number;

  // From sessions JOIN (null when no active session)
  session_status: string | null;
  model: string | null;
  session_error_category: string | null;
  session_error_message: string | null;
  latest_message_sent_at: string | null;
}

// ÔöÇÔöÇÔöÇ sessions ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export interface SessionRow {
  id: string;
  workspace_id: string;
  agent_type: string;
  model: string;
  agent_session_id: string | null;
  title: string | null;
  status: string;
  message_count: number;
  error_message: string | null;
  error_category: string | null;
  last_user_message_at: string | null;
  context_token_count: number;
  context_used_percent: number;
  is_hidden: boolean; // SQLite stores as INTEGER 0/1, coerced by coerceSessionBooleans
  updated_at: string;
}

/** Session joined with workspace info. */
export interface SessionWithDetailsRow extends SessionRow {
  slug: string | null;
  workspace_state: string | null;
}

// ÔöÇÔöÇÔöÇ messages ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export interface MessageRow {
  id: string;
  session_id: string;
  seq: number;
  role: string;
  content: string | null;
  turn_id: string | null;
  model: string | null;
  agent_message_id: string | null;
  sent_at: string | null;
  cancelled_at: string | null;
  parent_tool_use_id: string | null;
}

// ÔöÇÔöÇÔöÇ stats ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export interface StatsRow {
  workspaces: number;
  workspaces_ready: number;
  workspaces_archived: number;
  repositories: number;
  sessions: number;
  sessions_idle: number;
  sessions_working: number;
  messages: number;
}

/**
 * Typed query functions ÔÇö centralized DB reads for all route handlers.
 *
 * Every `as` cast lives here (once per query), not in routes.
 * Route handlers call these functions instead of inline SQL.
 */
import type Database from "better-sqlite3";
import type {
  RepositoryRow,
  RepositoryWithCountsRow,
  WorkspaceRow,
  WorkspaceWithDetailsRow,
  SessionRow,
  SessionWithDetailsRow,
  MessageRow,
  StatsRow,
} from "./types";

// ÔöÇÔöÇÔöÇ Workspace Queries ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

/**
 * Canonical workspace + repo + session JOIN.
 * Single source of truth ÔÇö reused by list, get-by-id, and by-repo queries.
 */
const WORKSPACE_DETAILS_SELECT = `
  SELECT
    w.id, w.repository_id, w.slug, w.title, w.git_branch,
    w.git_target_branch, w.state, w.status, w.current_session_id,
    w.pr_url, w.pr_number,
    w.setup_status, w.error_message, w.init_stage,
    w.updated_at,
    r.name as repo_name, r.root_path, r.git_default_branch,
    s.status as session_status, s.model,
    s.error_category as session_error_category,
    s.error_message as session_error_message,
    s.last_user_message_at as latest_message_sent_at
  FROM workspaces w
  LEFT JOIN repositories r ON w.repository_id = r.id
  LEFT JOIN sessions s ON w.current_session_id = s.id
`;

export function getAllWorkspaces(db: Database.Database): WorkspaceWithDetailsRow[] {
  return db
    .prepare(
      `
    ${WORKSPACE_DETAILS_SELECT}
    ORDER BY w.updated_at DESC
    LIMIT 100
  `
    )
    .all() as WorkspaceWithDetailsRow[];
}

export function getWorkspacesByRepo(
  db: Database.Database,
  state?: string
): WorkspaceWithDetailsRow[] {
  // Support comma-separated states (e.g. "ready,initializing")
  let stateFilter = "";
  let stateParams: string[] = [];
  if (state) {
    const states = state.split(",").map((s) => s.trim());
    stateFilter = `WHERE w.state IN (${states.map(() => "?").join(",")})`;
    stateParams = states;
  }
  return db
    .prepare(
      `
    SELECT
      w.id, w.repository_id, w.slug, w.title, w.git_branch,
      w.git_target_branch, w.state, w.status, w.current_session_id,
      w.pr_url, w.pr_number,
      w.setup_status, w.error_message, w.init_stage,
      w.updated_at,
      r.name as repo_name, r.sort_order as repo_sort_order, r.root_path,
      r.git_default_branch,
      s.status as session_status, s.model,
      s.error_category as session_error_category,
      s.error_message as session_error_message,
      s.last_user_message_at as latest_message_sent_at
    FROM workspaces w
    LEFT JOIN repositories r ON w.repository_id = r.id
    LEFT JOIN sessions s ON w.current_session_id = s.id
    ${stateFilter}
    ORDER BY r.sort_order, r.name, w.updated_at DESC
  `
    )
    .all(...stateParams) as WorkspaceWithDetailsRow[];
}

export function getWorkspaceById(
  db: Database.Database,
  id: string
): WorkspaceWithDetailsRow | undefined {
  return db
    .prepare(
      `
    ${WORKSPACE_DETAILS_SELECT}
    WHERE w.id = ?
  `
    )
    .get(id) as WorkspaceWithDetailsRow | undefined;
}

/** Used by withWorkspace middleware ÔÇö lighter query without session JOIN. */
export function getWorkspaceForMiddleware(
  db: Database.Database,
  id: string
): WorkspaceWithDetailsRow | undefined {
  return db
    .prepare(
      `
    SELECT w.*, r.root_path, r.git_default_branch, r.name as repo_name
    FROM workspaces w
    LEFT JOIN repositories r ON w.repository_id = r.id
    WHERE w.id = ?
  `
    )
    .get(id) as WorkspaceWithDetailsRow | undefined;
}

export function getWorkspaceRaw(db: Database.Database, id: string): WorkspaceRow | undefined {
  return db.prepare("SELECT * FROM workspaces WHERE id = ?").get(id) as WorkspaceRow | undefined;
}

/**
 * Look up workspaces by their current session IDs.
 * Used by the query engine for delta pushes ÔÇö when a session status changes,
 * we only need the affected workspace(s) instead of re-querying everything.
 */
export function getWorkspacesBySessionIds(
  db: Database.Database,
  sessionIds: string[]
): WorkspaceWithDetailsRow[] {
  if (sessionIds.length === 0) return [];
  const placeholders = sessionIds.map(() => "?").join(",");
  return db
    .prepare(
      `
    SELECT
      w.id, w.repository_id, w.slug, w.title, w.git_branch,
      w.git_target_branch, w.state, w.status, w.current_session_id,
      w.pr_url, w.pr_number,
      w.setup_status, w.error_message, w.init_stage,
      w.updated_at,
      r.name as repo_name, r.sort_order as repo_sort_order, r.root_path,
      r.git_default_branch,
      s.status as session_status, s.model,
      s.error_category as session_error_category,
      s.error_message as session_error_message,
      s.last_user_message_at as latest_message_sent_at
    FROM workspaces w
    LEFT JOIN repositories r ON w.repository_id = r.id
    LEFT JOIN sessions s ON w.current_session_id = s.id
