import type { Meta, StoryObj } from "@storybook/react-vite";
import type { Workspace, DiffStats } from "@/shared/types";
import { WorkspaceItem } from "./WorkspaceItem";

const BASE_WORKSPACE: Workspace = {
  id: "ws-1",
  repository_id: "repo-1",
  slug: "addis-ababa",
  title: "Addis Ababa",
  git_branch: "zvadaadam/restart-dev-server",
  git_target_branch: "main",
  state: "ready",
  current_session_id: "session-1",
  session_status: "idle",
  model: "sonnet",
  session_error_category: null,
  session_error_message: null,
  latest_message_sent_at: new Date(Date.now() - 120_000).toISOString(),
  updated_at: new Date(Date.now() - 120_000).toISOString(),
  repo_name: "sample-backend",
  root_path: "/code/sample-backend",
  workspace_path: "/code/sample-backend/.opendevs/addis-ababa",
  setup_status: "none",
  error_message: null,
};

function ws(overrides: Partial<Workspace>): Workspace {
  return { ...BASE_WORKSPACE, ...overrides };
}

const DIFF: DiffStats = { additions: 713, deletions: 2 };
const DIFF_BIG: DiffStats = { additions: 7277, deletions: 17 };
const DIFF_NONE: DiffStats = { additions: 0, deletions: 0 };

const noop = () => {};

const meta: Meta<typeof WorkspaceItem> = {
  title: "Sidebar/WorkspaceItem",
  component: WorkspaceItem,
  decorators: [
    (Story) => (
      <div className="bg-bg-sidebar w-[320px] rounded-lg p-1.5">
        <ul className="flex flex-col">
          <Story />
        </ul>
      </div>
    ),
  ],
  args: {
    onClick: noop,
    onArchive: noop,
  },
};
export default meta;

type Story = StoryObj<typeof WorkspaceItem>;

/** All status states side by side for quick comparison */
export const AllStates: Story = {
  render: () => (
    <div className="bg-bg-sidebar w-[320px] rounded-lg p-1.5">
      <ul className="flex flex-col">
        {/* Working ÔÇö PixelGrid animation + duration */}
        <WorkspaceItem
          workspace={ws({
            id: "working",
            session_status: "working",
            git_branch: "zvadaadam/restart-dev-server",
            slug: "addis-ababa",
            latest_message_sent_at: new Date(Date.now() - 90_000).toISOString(),
          })}
          isActive={false}
          diffStats={DIFF}
          onClick={noop}
          onArchive={noop}
        />

        {/* Unread ÔÇö gold dot + "Needs response" */}
        <WorkspaceItem
          workspace={ws({
            id: "unread",
            session_status: "needs_response",
            git_branch: "zvadaadam/fix-websocket-conn",
            slug: "rome-v1",
            updated_at: new Date(Date.now() - 600_000).toISOString(),
          })}
          isActive={false}
          diffStats={{ additions: 229, deletions: 12 }}
          onClick={noop}
          onArchive={noop}
        />

        {/* Error ÔÇö red dot indicator */}
        <WorkspaceItem
          workspace={ws({
            id: "error",
            session_status: "error",
            git_branch: "zvadaadam/fix-triple-sandbox",
            slug: "vienna",
            updated_at: new Date(Date.now() - 3600_000).toISOString(),
          })}
          isActive={false}
          diffStats={{ additions: 1131, deletions: 297 }}
          onClick={noop}
          onArchive={noop}
        />

        {/* Idle ÔÇö no icon, time ago */}
        <WorkspaceItem
          workspace={ws({
            id: "idle-recent",
            session_status: "idle",
            git_branch: "zvadaadam/chat-image-url-input",
            slug: "nairobi",
            updated_at: new Date(Date.now() - 7 * 3600_000).toISOString(),
          })}
          isActive={false}
          diffStats={DIFF_NONE}
          onClick={noop}
          onArchive={noop}
        />

        {/* Idle ÔÇö no icon, days ago, with changes */}
        <WorkspaceItem
          workspace={ws({
            id: "idle-old",
            session_status: "idle",
            git_branch: "zvadaadam/secure-api-key-passing",
            slug: "istanbul-v1",
            updated_at: new Date(Date.now() - 7 * 24 * 3600_000).toISOString(),
          })}
          isActive={false}
          diffStats={{ additions: 62, deletions: 66 }}
          onClick={noop}
          onArchive={noop}
        />

        {/* Idle ÔÇö months ago */}
        <WorkspaceItem
          workspace={ws({
            id: "idle-months",
            session_status: "idle",
            git_branch: "simplify-claude-md",
            slug: "muscat",
            updated_at: new Date(Date.now() - 60 * 24 * 3600_000).toISOString(),
          })}
          isActive={false}
          diffStats={{ additions: 169, deletions: 303 }}
          onClick={noop}
          onArchive={noop}
        />
      </ul>
    </div>
  ),
};

/** Working state with PixelGrid animation */
export const Working: Story = {
  args: {
    workspace: ws({
      session_status: "working",
      latest_message_sent_at: new Date(Date.now() - 90_000).toISOString(),
    }),
    isActive: false,
    diffStats: DIFF,
  },
};

/** Working + selected (active) */
export const WorkingSelected: Story = {
  args: {
    workspace: ws({
      session_status: "working",
      latest_message_sent_at: new Date(Date.now() - 90_000).toISOString(),
    }),
    isActive: true,
    diffStats: DIFF_BIG,
  },
};

/** Unread messages ÔÇö gold dot indicator */
export const Unread: Story = {
  args: {
    workspace: ws({
      session_status: "needs_response",
      git_branch: "zvadaadam/fix-websocket-conn",
      slug: "rome-v1",
    }),
    isActive: false,
    diffStats: { additions: 229, deletions: 12 },
  },
};

/** Unread + selected */
export const UnreadSelected: Story = {
  args: {
    workspace: ws({
