 1Ôćĺimport { Hono } from "hono";
 2Ôćĺimport { withWorkspace } from "../middleware/workspace-loader";
 3Ôćĺimport { runGh, getPrStatus } from "../services/gh.service";
 4Ôćĺimport { getDatabase } from "../lib/database";
 5Ôćĺimport { invalidate } from "../services/query-engine";
 6Ôćĺimport { autoProgressStatus } from "../services/workspace-status.service";
 7Ôćĺimport type { WorkspaceWithDetailsRow } from "../db";
 8Ôćĺ
 9Ôćĺtype Env = { Variables: { workspace: WorkspaceWithDetailsRow; workspacePath: string } };
10Ôćĺconst app = new Hono<Env>();
11Ôćĺ
12Ôćĺ// gh CLI status check -- cached on frontend with long staleTime
13Ôćĺapp.get("/gh-status", async (c) => {
14Ôćĺ  const versionResult = await runGh(["--version"], { cwd: process.cwd(), timeoutMs: 2000 });
15Ôćĺ  if (!versionResult.success) return c.json({ isInstalled: false, isAuthenticated: false });
16Ôćĺ  const authResult = await runGh(["auth", "status"], { cwd: process.cwd(), timeoutMs: 5000 });
17Ôćĺ  return c.json({ isInstalled: true, isAuthenticated: authResult.success });
18Ôćĺ});
19Ôćĺ
20Ôćĺ// PR status -- async, fork-aware, explicit errors
21Ôćĺ// Side-effect: persists pr_url on first discovery + triggers auto-derive
22Ôćĺapp.get("/workspaces/:id/pr-status", withWorkspace, async (c) => {
23Ôćĺ  const workspace = c.get("workspace");
24Ôćĺ  const workspacePath = c.get("workspacePath");
25Ôćĺ  const result = await getPrStatus(workspacePath);
26Ôćĺ
27Ôćĺ  let needsInvalidation = false;
28Ôćĺ
29Ôćĺ  // Persist PR URL when we first discover a PR (enables auto-derive)
30Ôćĺ  if (result.has_pr && result.pr_url && result.pr_url !== workspace.pr_url) {
31Ôćĺ    const db = getDatabase();
32Ôćĺ    db.prepare("UPDATE workspaces SET pr_url = ?, pr_number = ? WHERE id = ?")
33Ôćĺ      .run(result.pr_url, result.pr_number ?? null, workspace.id);
34Ôćĺ    autoProgressStatus(workspace.id, "in-review");
35Ôćĺ    needsInvalidation = true;
36Ôćĺ  }
