 84Ôćĺ/**
 85Ôćĺ * Handle an incoming q:* frame from an authenticated connection.
 86Ôćĺ * Registered as onQueryFrame in ws.service protocol handlers.
 87Ôćĺ */
 88Ôćĺexport function handleFrame(connectionId: string, msg: QueryParams): void {
 89Ôćĺ  const type = typeof msg.type === "string" ? msg.type : "unknown";
 90Ôćĺ
