129Ôćĺ/** Remove all subscriptions for a connection (cleanup on disconnect). */
130Ôćĺexport function removeSubs(connectionId: string): void {
131Ôćĺ  const connSubs = subs.get(connectionId);
132Ôćĺ  if (connSubs) {
133Ôćĺ    for (const [subId, sub] of connSubs) {
134Ôćĺ      if (sub.resource === "messages") {
135Ôćĺ        messageCursors.delete(`${connectionId}:${subId}`);
136Ôćĺ      }
137Ôćĺ    }
138Ôćĺ    subs.delete(connectionId);
