286Ôćĺ        }
287Ôćĺ      }
288Ôćĺ    }
289Ôćĺ
290Ôćĺ    sendFrame(connectionId, { type: "q:snapshot", id, data });
291Ôćĺ  } catch (err) {
292Ôćĺ    sendFrame(connectionId, {
293Ôćĺ      type: "q:error",
294Ôćĺ      id,
295Ôćĺ      code: "SUBSCRIBE_ERROR",
296Ôćĺ      message: err instanceof Error ? err.message : "Subscribe failed",
297Ôćĺ    });
298Ôćĺ  }
299Ôćĺ}
300Ôćĺ
301Ôćĺfunction handleUnsubscribe(connectionId: string, msg: UnsubscribeFrameInput): void {
302Ôćĺ  const { id } = msg;
303Ôćĺ
304Ôćĺ  const connSubs = subs.get(connectionId);
305Ôćĺ  if (!connSubs) return;
306Ôćĺ
307Ôćĺ  const sub = connSubs.get(id);
308Ôćĺ  if (sub) {
