310Ôćĺ    if (sub.resource === "messages") {
311Ôćĺ      messageCursors.delete(`${connectionId}:${id}`);
312Ôćĺ    }
313Ôćĺ    connSubs.delete(id);
314Ôćĺ    if (connSubs.size === 0) subs.delete(connectionId);
315Ôćĺ  }
316Ôćĺ}
317Ôćĺ
318Ôćĺfunction handleMutate(connectionId: string, msg: MutateFrameInput): void {
319Ôćĺ  const { id, action, params } = msg;
320Ôćĺ
321Ôćĺ  try {
322Ôćĺ    const result = runMutation(action, params);
323Ôćĺ    sendFrame(connectionId, {
324Ôćĺ      type: "q:mutate_result",
325Ôćĺ      id,
