327Ôćĺ      data: result,
328Ôćĺ    });
329Ôćĺ  } catch (err) {
330Ôćĺ    sendFrame(connectionId, {
331Ôćĺ      type: "q:mutate_result",
332Ôćĺ      id,
333Ôćĺ      success: false,
334Ôćĺ      error: err instanceof Error ? err.message : "Mutation failed",
