338Ôćĺ
339Ôćĺasync function handleCommand(connectionId: string, msg: CommandFrameInput): Promise<void> {
340Ôćĺ  const { id, command, params } = msg;
341Ôćĺ
342Ôćĺ  try {
343Ôćĺ    const result = await runCommand(toCommandName(command), params);
344Ôćĺ    sendFrame(connectionId, {
345Ôćĺ      type: "q:command_ack",
