498Ôćĺ      }
499Ôćĺ      setWorkspaceStatus(workspaceId, status as WorkspaceStatus);
500Ôćĺ      invalidate(["workspaces", "stats"]);
501Ôćĺ      return { success: true };
502Ôćĺ    })
503Ôćĺ    .exhaustive();
504Ôćĺ}
