 95Ôćĺapp.patch("/workspaces/:id", async (c) => {
 96Ôćĺ  const db = getDatabase();
 97Ôćĺ  const id = c.req.param("id");
 98Ôćĺ  const { state, status } = parseBody(PatchWorkspaceBody, await c.req.json());
 99Ôćĺ
100Ôćĺ  if (status) {
101Ôćĺ    setWorkspaceStatus(id, status);
102Ôćĺ  }
103Ôćĺ
104Ôćĺ  if (state) {
105Ôćĺ    db.prepare("UPDATE workspaces SET state = ? WHERE id = ?").run(state, id);
106Ôćĺ
107Ôćĺ    if (state === "archived") {
108Ôćĺ      autoProgressStatus(id, "done", { force: true });
109Ôćĺ
110Ôćĺ      // Run archive lifecycle hook (best-effort)
111Ôćĺ      try {
112Ôćĺ        const ws = getWorkspaceById(db, id);
113Ôćĺ        if (ws && ws.root_path) {
114Ôćĺ          const wsPath = computeWorkspacePath(ws);
115Ôćĺ          const manifest = readManifestWithFallback(wsPath, ws.root_path);
116Ôćĺ          const archiveCmd = manifest ? getArchiveCommand(manifest) : null;
117Ôćĺ          if (archiveCmd) {
118Ôćĺ            const archiveEnv = getOpenDevsEnv(manifest!, {
119Ôćĺ              id: ws.id,
120Ôćĺ              rootPath: ws.root_path,
121Ôćĺ              workspacePath: wsPath,
122Ôćĺ            });
123Ôćĺ            const archiveProc = spawn("sh", ["-c", archiveCmd], {
124Ôćĺ              cwd: wsPath,
125Ôćĺ              env: { ...process.env, ...archiveEnv },
126Ôćĺ              stdio: "ignore",
127Ôćĺ              detached: false,
128Ôćĺ            });
129Ôćĺ            archiveProc.on("error", (err) => {
130Ôćĺ              console.error(`Archive hook error for workspace ${id}:`, err.message);
131Ôćĺ            });
132Ôćĺ            archiveProc.unref();
133Ôćĺ          }
134Ôćĺ        }
135Ôćĺ      } catch (err) {
136Ôćĺ        console.warn("[WORKSPACE] Archive lifecycle hook failed (continuing):", err);
137Ôćĺ      }
138Ôćĺ    }
139Ôćĺ
140Ôćĺ    // Unarchive: restore done Ôćĺ in-progress
141Ôćĺ    if (state === "ready") {
142Ôćĺ      const ws = getWorkspaceRaw(db, id);
143Ôćĺ      if (ws?.status === "done") {
144Ôćĺ        autoProgressStatus(id, "in-progress", { force: true });
145Ôćĺ      }
146Ôćĺ    }
147Ôćĺ  }
148Ôćĺ  const updated = getWorkspaceRaw(db, id);
149Ôćĺ  invalidate(["workspaces", "sessions", "stats"]);
150Ôćĺ  return c.json(updated);
151Ôćĺ});
