223Ôćĺ  // Branch from origin/<parent_branch> when available (fetched above).
224Ôćĺ  // Falls back to local <parent_branch> if remote doesn't exist.
225Ôćĺ  const worktreeBase = await (async () => {
226Ôćĺ    try {
227Ôćĺ      await execFileAsync(
228Ôćĺ        "git",
229Ôćĺ        ["show-ref", "--verify", "--quiet", `refs/remotes/origin/${parent_branch}`],
230Ôćĺ        {
231Ôćĺ          cwd: repo.root_path!,
232Ôćĺ          timeout: 2000,
233Ôćĺ        }
234Ôćĺ      );
235Ôćĺ      return `origin/${parent_branch}`;
236Ôćĺ    } catch {
237Ôćĺ      return parent_branch;
238Ôćĺ    }
239Ôćĺ  })();
