241Ôćĺ  const workspacePath = path.join(repo.root_path!, ".opendevs", workspace_name);
242Ôćĺ
243Ôćĺ  // Fire-and-forget: run the init pipeline async (don't await).
244Ôćĺ  // Pipeline handles: worktree creation Ôćĺ deps install Ôćĺ .env copy Ôćĺ session creation.
245Ôćĺ  // Progress events flow: stdout Ôćĺ Electron main process Ôćĺ IPC events Ôćĺ Frontend.
246Ôćĺ  // On fatal failure: reverse cleanup (rm dir, prune worktree, delete branch).
247Ôćĺ  initializeWorkspace({
248Ôćĺ    workspaceId,
249Ôćĺ    repositoryId: repository_id,
250Ôćĺ    repoRootPath: repo.root_path!,
251Ôćĺ    workspacePath,
252Ôćĺ    branchName: placeholderBranchName,
253Ôćĺ    worktreeBase,
254Ôćĺ    parentBranch: parent_branch,
255Ôćĺ  })
256Ôćĺ    .then(() => {
257Ôćĺ      // Workspace is ready ÔÇö check for manifest setup script
258Ôćĺ      const manifest = readManifestWithFallback(workspacePath, repo.root_path!);
259Ôćĺ      const setupCmd = manifest ? getSetupCommand(manifest) : null;
260Ôćĺ      if (setupCmd && manifest) {
261Ôćĺ        db.prepare("UPDATE workspaces SET setup_status = 'running' WHERE id = ?").run(workspaceId);
262Ôćĺ        const setupEnv = getOpenDevsEnv(manifest, {
263Ôćĺ          id: workspaceId,
264Ôćĺ          rootPath: repo.root_path!,
