272Ôćĺ      // but if something truly unexpected escapes, don't leave workspace stuck.
273Ôćĺ      console.error("[WORKSPACE] Unhandled init pipeline error:", err);
274Ôćĺ      try {
275Ôćĺ        db.prepare(
