282Ôćĺ  const workspace = getWorkspaceForMiddleware(db, workspaceId);
283Ôćĺ  if (!workspace) throw new NotFoundError("Workspace not found after creation");
284Ôćĺ
285Ôćĺ  // Push immediately so clients see the workspace in 'initializing' state.
286Ôćĺ  // Query-protocol subscribers get snapshots + q:invalidate for unmounted caches.
287Ôćĺ  // The init pipeline will invalidate again when it transitions to 'ready'.
288Ôćĺ  invalidate(["workspaces", "stats"]);
