121Ôćĺ/**
122Ôćĺ * Derive display status from workspace data
123Ôćĺ *
124Ôćĺ * Priority logic:
125Ôćĺ * 1. Error ÔÇö session in error state
126Ôćĺ * 2. Unread ÔÇö agent needs user response (needs_response / needs_plan_response)
127Ôćĺ * 3. Working ÔÇö agent actively processing
128Ôćĺ * 4. Idle ÔÇö dormant
129Ôćĺ *
130Ôćĺ * @param workspace Workspace data with session info
131Ôćĺ * @returns Derived display status for UI rendering
132Ôćĺ */
133Ôćĺexport function getDisplayStatus(workspace: Workspace): DisplayStatus {
134Ôćĺ  const status = workspace.session_status;
135Ôćĺ
136Ôćĺ  if (status === "error") return "error";
137Ôćĺ  if (status === "needs_response" || status === "needs_plan_response") return "unread";
138Ôćĺ  if (status === "working") return "working";
139Ôćĺ  return "idle";
140Ôćĺ}
141Ôćĺ
142Ôćĺ/**
143Ôćĺ * Check if workspace needs user attention.
144Ôćĺ * In V2, attention state is derived from session_status (needs_response / needs_plan_response).
145Ôćĺ */
146Ôćĺexport function getUnreadCount(workspace: Workspace): number {
147Ôćĺ  const status = workspace.session_status;
148Ôćĺ  return status === "needs_response" || status === "needs_plan_response" ? 1 : 0;
149Ôćĺ}
150Ôćĺ
151Ôćĺ/**
152Ôćĺ * Sort workspaces by status priority
153Ôćĺ * Higher priority statuses appear first
154Ôćĺ *
155Ôćĺ * @param workspaces Array of workspaces to sort
156Ôćĺ * @returns Sorted array (original array not mutated)
157Ôćĺ */
158Ôćĺexport function sortByStatusPriority<T extends Workspace>(workspaces: T[]): T[] {
159Ôćĺ  return [...workspaces].sort((a, b) => {
160Ôćĺ    const statusA = getDisplayStatus(a);
161Ôćĺ    const statusB = getDisplayStatus(b);
162Ôćĺ    const priorityA = STATUS_CONFIG[statusA].priority;
163Ôćĺ    const priorityB = STATUS_CONFIG[statusB].priority;
164Ôćĺ
165Ôćĺ    // Higher priority first
166Ôćĺ    if (priorityA !== priorityB) {
167Ôćĺ      return priorityB - priorityA;
168Ôćĺ    }
169Ôćĺ
170Ôćĺ    // Same priority: sort by latest activity (most recent first)
171Ôćĺ    const timeA = new Date(a.updated_at).getTime();
172Ôćĺ    const timeB = new Date(b.updated_at).getTime();
173Ôćĺ    return timeB - timeA;
174Ôćĺ  });
175Ôćĺ}
176Ôćĺ
177Ôćĺ/**
178Ôćĺ * Group workspaces by display status
179Ôćĺ * Used for rendering section headers in expanded sidebar
180Ôćĺ *
181Ôćĺ * @param workspaces Array of workspaces to group
182Ôćĺ * @returns Object with status as keys, workspace arrays as values
183Ôćĺ */
184Ôćĺexport function groupByStatus<T extends Workspace>(
185Ôćĺ  workspaces: T[]
186Ôćĺ): Partial<Record<DisplayStatus, T[]>> {
187Ôćĺ  const groups: Partial<Record<DisplayStatus, T[]>> = {};
188Ôćĺ
189Ôćĺ  workspaces.forEach((workspace) => {
190Ôćĺ    const status = getDisplayStatus(workspace);
191Ôćĺ    if (!groups[status]) {
192Ôćĺ      groups[status] = [];
193Ôćĺ    }
194Ôćĺ    groups[status]!.push(workspace);
195Ôćĺ  });
196Ôćĺ
197Ôćĺ  return groups;
198Ôćĺ}
