200Ôćĺ/**
201Ôćĺ * Get aggregate status counts for a repository
202Ôćĺ * Used for collapsed sidebar status indicators
203Ôćĺ *
204Ôćĺ * @param workspaces Workspaces in a repository
205Ôćĺ * @returns Count of each status type
206Ôćĺ */
207Ôćĺexport function getStatusCounts(workspaces: Workspace[]): Record<DisplayStatus, number> {
208Ôćĺ  const counts: Record<DisplayStatus, number> = {
209Ôćĺ    error: 0,
210Ôćĺ    unread: 0,
211Ôćĺ    working: 0,
212Ôćĺ    idle: 0,
213Ôćĺ  };
214Ôćĺ
215Ôćĺ  workspaces.forEach((workspace) => {
216Ôćĺ    const status = getDisplayStatus(workspace);
217Ôćĺ    counts[status]++;
218Ôćĺ  });
219Ôćĺ
220Ôćĺ  return counts;
221Ôćĺ}
