223Ôćĺ/**
224Ôćĺ * Get total unread count for a repository
225Ôćĺ * Sums unread across all workspaces
226Ôćĺ */
227Ôćĺexport function getRepoUnreadCount(workspaces: Workspace[]): number {
228Ôćĺ  return workspaces.reduce((sum, workspace) => {
229Ôćĺ    return sum + getUnreadCount(workspace);
230Ôćĺ  }, 0);
231Ôćĺ}
232Ôćĺ
233Ôćĺ/**
234Ôćĺ * Get highest priority status for a repository
235Ôćĺ * Used for collapsed sidebar badge color
236Ôćĺ *
237Ôćĺ * @param workspaces Workspaces in a repository
238Ôćĺ * @returns The highest priority status present
239Ôćĺ */
240Ôćĺexport function getRepoPriorityStatus(workspaces: Workspace[]): DisplayStatus {
241Ôćĺ  let highestPriority = StatusPriority.IDLE;
242Ôćĺ  let highestStatus: DisplayStatus = "idle";
243Ôćĺ
244Ôćĺ  workspaces.forEach((workspace) => {
245Ôćĺ    const status = getDisplayStatus(workspace);
246Ôćĺ    const priority = STATUS_CONFIG[status].priority;
247Ôćĺ
248Ôćĺ    if (priority > highestPriority) {
249Ôćĺ      highestPriority = priority;
250Ôćĺ      highestStatus = status;
251Ôćĺ    }
252Ôćĺ  });
253Ôćĺ
254Ôćĺ  return highestStatus;
255Ôćĺ}
