 5Ôćĺ/**
 6Ôćĺ * Auto-progress a workspace's workflow status.
 7Ôćĺ *
 8Ôćĺ * Rules:
 9Ôćĺ * - Sticky states (backlog, canceled) resist auto-progression unless forced
10Ôćĺ * - Won't regress (in-review won't go back to in-progress)
11Ôćĺ * - Force mode (used by archive) overrides both guards
12Ôćĺ *
13Ôćĺ * IMPORTANT: Does NOT call invalidate(). The caller is responsible for
14Ôćĺ * invalidation after its own DB writes. This prevents double WS pushes.
15Ôćĺ */
16Ôćĺexport function autoProgressStatus(
17Ôćĺ  workspaceId: string,
18Ôćĺ  target: WorkspaceStatus,
19Ôćĺ  opts: { force?: boolean } = {},
20Ôćĺ): void {
21Ôćĺ  const db = getDatabase();
22Ôćĺ  const ws = getWorkspaceRaw(db, workspaceId);
23Ôćĺ  if (!ws) return;
24Ôćĺ
25Ôćĺ  const current = ws.status as WorkspaceStatus;
26Ôćĺ
27Ôćĺ  if (!opts.force) {
28Ôćĺ    // Sticky states resist auto-progression (backlog, canceled)
29Ôćĺ    if (STICKY_STATUSES.has(current)) return;
30Ôćĺ    // Don't regress (in-review Ôćĺ in-progress is wrong)
31Ôćĺ    if (STATUS_RANK[target] <= STATUS_RANK[current]) return;
32Ôćĺ  }
33Ôćĺ
34Ôćĺ  db.prepare("UPDATE workspaces SET status = ? WHERE id = ?").run(target, workspaceId);
35Ôćĺ}
