37Ôćĺ/**
38Ôćĺ * Explicitly set workspace status (user override). No sticky/flow guards.
39Ôćĺ * Used by the updateWorkspaceStatus mutation.
40Ôćĺ */
41Ôćĺexport function setWorkspaceStatus(workspaceId: string, status: WorkspaceStatus): void {
42Ôćĺ  const db = getDatabase();
43Ôćĺ  db.prepare("UPDATE workspaces SET status = ? WHERE id = ?").run(status, workspaceId);
44Ôćĺ}
