 53Ôćĺinterface UnsubscribeFrameInput {
 54Ôćĺ  id: string;
 55Ôćĺ}
 56Ôćĺ
 57Ôćĺinterface MutateFrameInput {
 58Ôćĺ  id: string;
 59Ôćĺ  action: string;
 60Ôćĺ  params: QueryParams;
 61Ôćĺ}
 62Ôćĺ
 63Ôćĺinterface CommandFrameInput {
 64Ôćĺ  id: string;
 65Ôćĺ  command: string;
 66Ôćĺ  params: QueryParams;
 67Ôćĺ}
 68Ôćĺ
 69Ôćĺinterface Sub {
 70Ôćĺ  id: string;
 71Ôćĺ  resource: QueryResource;
 72Ôćĺ  params: QueryParams;
 73Ôćĺ}
 74Ôćĺ
 75Ôćĺ/** Per-connection active subscriptions, keyed by client-assigned sub ID. */
 76Ôćĺconst subs = new Map<string, Map<string, Sub>>();
 77Ôćĺ
 78Ôćĺ/** For messages: track last seen seq per subscription for delta push.
 79Ôćĺ *  Key: `${connectionId}:${subId}` Ôćĺ lastSeq */
 80Ôćĺconst messageCursors = new Map<string, number>();
 81Ôćĺ
 82Ôćĺ// ---- Public API ----
 83Ôćĺ
 84Ôćĺ/**
 85Ôćĺ * Handle an incoming q:* frame from an authenticated connection.
 86Ôćĺ * Registered as onQueryFrame in ws.service protocol handlers.
 87Ôćĺ */
 88Ôćĺexport function handleFrame(connectionId: string, msg: QueryParams): void {
 89Ôćĺ  const type = typeof msg.type === "string" ? msg.type : "unknown";
 90Ôćĺ
 91Ôćĺ  try {
 92Ôćĺ    match(type)
 93Ôćĺ      .with("q:request", () => {
 94Ôćĺ        handleRequest(connectionId, parseResourceFrame(msg));
 95Ôćĺ      })
 96Ôćĺ      .with("q:subscribe", () => {
 97Ôćĺ        handleSubscribe(connectionId, parseResourceFrame(msg));
 98Ôćĺ      })
 99Ôćĺ      .with("q:unsubscribe", () => {
100Ôćĺ        handleUnsubscribe(connectionId, parseUnsubscribeFrame(msg));
101Ôćĺ      })
102Ôćĺ      .with("q:mutate", () => {
103Ôćĺ        handleMutate(connectionId, parseMutateFrame(msg));
104Ôćĺ      })
105Ôćĺ      .with("q:command", () => {
106Ôćĺ        handleCommand(connectionId, parseCommandFrame(msg));
107Ôćĺ      })
108Ôćĺ      .with("q:tool_response", () => {
109Ôćĺ        handleToolResponse(msg);
110Ôćĺ      })
111Ôćĺ      .otherwise(() => {
112Ôćĺ        sendFrame(connectionId, {
113Ôćĺ          type: "q:error",
114Ôćĺ          id: getFrameId(msg),
115Ôćĺ          code: "UNKNOWN_FRAME",
116Ôćĺ          message: `Unknown query frame type: ${type}`,
117Ôćĺ        });
118Ôćĺ      });
119Ôćĺ  } catch (err) {
120Ôćĺ    sendFrame(connectionId, {
121Ôćĺ      type: "q:error",
122Ôćĺ      id: getFrameId(msg),
123Ôćĺ      code: "INVALID_FRAME",
124Ôćĺ      message: err instanceof Error ? err.message : "Invalid query frame",
125Ôćĺ    });
126Ôćĺ  }
127Ôćĺ}
128Ôćĺ
129Ôćĺ/** Remove all subscriptions for a connection (cleanup on disconnect). */
130Ôćĺexport function removeSubs(connectionId: string): void {
131Ôćĺ  const connSubs = subs.get(connectionId);
132Ôćĺ  if (connSubs) {
133Ôćĺ    for (const [subId, sub] of connSubs) {
134Ôćĺ      if (sub.resource === "messages") {
135Ôćĺ        messageCursors.delete(`${connectionId}:${subId}`);
136Ôćĺ      }
137Ôćĺ    }
138Ôćĺ    subs.delete(connectionId);
139Ôćĺ  }
140Ôćĺ}
141Ôćĺ
142Ôćĺ/** Optional context for targeted invalidation (e.g., which sessions changed). */
143Ôćĺinterface InvalidateContext {
144Ôćĺ  sessionIds?: string[];
145Ôćĺ}
146Ôćĺ
147Ôćĺ/**
148Ôćĺ * Push-first invalidation: re-run queries for active subscribers and push
149Ôćĺ * fresh snapshots or deltas.
150Ôćĺ *
151Ôćĺ * Messages use q:delta (cursor-based) instead of full snapshots.
152Ôćĺ * When `ctx.sessionIds` is provided, workspace subscribers receive a targeted
153Ôćĺ * q:delta (only the changed workspaces) instead of a full q:snapshot.
154Ôćĺ */
155Ôćĺexport function invalidate(resources: QueryResource[], ctx?: InvalidateContext): void {
156Ôćĺ  if (resources.includes("stats")) {
157Ôćĺ    resetStatsCache();
158Ôćĺ  }
159Ôćĺ
160Ôćĺ  // Phase 1: Push fresh data to active subscribers
161Ôćĺ  for (const [connectionId, connSubs] of subs) {
162Ôćĺ    if (!getConnection(connectionId)) {
163Ôćĺ      removeSubs(connectionId);
164Ôćĺ      continue;
165Ôćĺ    }
166Ôćĺ
167Ôćĺ    for (const [subId, sub] of connSubs) {
168Ôćĺ      if (!resources.includes(sub.resource)) continue;
169Ôćĺ
170Ôćĺ      if (sub.resource === "messages") {
171Ôćĺ        // Messages: push delta (new messages since last cursor)
172Ôćĺ        pushMessageDelta(connectionId, subId, sub.params);
173Ôćĺ      } else if (sub.resource === "workspaces" && ctx?.sessionIds?.length) {
174Ôćĺ        // Workspaces with session context: try targeted delta
175Ôćĺ        try {
176Ôćĺ          const db = getDatabase();
177Ôćĺ          const stateFilter = readStringParam(sub.params, "state") ?? "ready,initializing";
178Ôćĺ          const allowedStates = new Set(stateFilter.split(",").map((s) => s.trim()));
179Ôćĺ          const changedWorkspaces = getWorkspacesBySessionIds(db, ctx.sessionIds).filter((ws) =>
180Ôćĺ            allowedStates.has(ws.state)
181Ôćĺ          );
182Ôćĺ          if (changedWorkspaces.length > 0) {
183Ôćĺ            const withPaths = changedWorkspaces.map((ws) => ({
184Ôćĺ              ...ws,
185Ôćĺ              workspace_path: computeWorkspacePath(ws),
186Ôćĺ            }));
187Ôćĺ            sendFrame(connectionId, {
188Ôćĺ              type: "q:delta",
189Ôćĺ              id: subId,
190Ôćĺ              upserted: withPaths,
191Ôćĺ            });
192Ôćĺ          } else {
193Ôćĺ            // Session IDs didn't match any workspaces ÔÇö fall back to full snapshot
194Ôćĺ            const data = runQuery(sub.resource, sub.params);
195Ôćĺ            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
196Ôćĺ          }
197Ôćĺ        } catch (err) {
198Ôćĺ          // Delta lookup failed ÔÇö fall back to full snapshot
199Ôćĺ          console.error(`[QueryEngine] Workspace delta failed, falling back to snapshot:`, err);
200Ôćĺ          try {
201Ôćĺ            const data = runQuery(sub.resource, sub.params);
202Ôćĺ            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
203Ôćĺ          } catch (snapErr) {
204Ôćĺ            console.error(`[QueryEngine] Snapshot fallback also failed:`, snapErr);
205Ôćĺ          }
206Ôćĺ        }
207Ôćĺ      } else if (sub.resource === "session" && ctx?.sessionIds?.length) {
208Ôćĺ        // Session with context: only push if this subscription's session is in the changed set
209Ôćĺ        const subscribedSessionId = readStringParam(sub.params, "sessionId");
210Ôćĺ        if (subscribedSessionId && ctx.sessionIds.includes(subscribedSessionId)) {
211Ôćĺ          try {
212Ôćĺ            const data = runQuery(sub.resource, sub.params);
213Ôćĺ            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
214Ôćĺ          } catch (err) {
215Ôćĺ            console.error(`[QueryEngine] Session snapshot push failed:`, err);
216Ôćĺ          }
217Ôćĺ        }
218Ôćĺ        // If session not in changed set, skip the push
219Ôćĺ      } else {
220Ôćĺ        // Other resources: push full snapshot
221Ôćĺ        try {
222Ôćĺ          const data = runQuery(sub.resource, sub.params);
223Ôćĺ          sendFrame(connectionId, {
224Ôćĺ            type: "q:snapshot",
225Ôćĺ            id: subId,
226Ôćĺ            data,
227Ôćĺ          });
228Ôćĺ        } catch (err) {
229Ôćĺ          console.error(`[QueryEngine] Snapshot push failed for ${sub.resource}:`, err);
230Ôćĺ        }
231Ôćĺ      }
232Ôćĺ    }
233Ôćĺ  }
234Ôćĺ}
