236Ôćĺ// ---- Frame Handlers ----
237Ôćĺ
238Ôćĺfunction handleRequest(connectionId: string, msg: ResourceFrameInput): void {
239Ôćĺ  const { id, resource, params } = msg;
240Ôćĺ
241Ôćĺ  try {
242Ôćĺ    const typedResource = toQueryResource(resource);
243Ôćĺ    const data = runQuery(typedResource, params);
244Ôćĺ    sendFrame(connectionId, { type: "q:response", id, data });
245Ôćĺ  } catch (err) {
246Ôćĺ    sendFrame(connectionId, {
247Ôćĺ      type: "q:error",
248Ôćĺ      id,
249Ôćĺ      code: "QUERY_ERROR",
250Ôćĺ      message: err instanceof Error ? err.message : "Query failed",
251Ôćĺ    });
252Ôćĺ  }
253Ôćĺ}
254Ôćĺ
255Ôćĺfunction handleSubscribe(connectionId: string, msg: ResourceFrameInput): void {
256Ôćĺ  const { id, resource, params } = msg;
257Ôćĺ
258Ôćĺ  // Validate resource upfront ÔÇö fail fast before running query
259Ôćĺ  const typedResource = toQueryResource(resource);
260Ôćĺ
261Ôćĺ  // Send initial snapshot ÔÇö only register subscription if query succeeds
262Ôćĺ  // (avoids zombie subscriptions when runQuery throws on invalid params)
263Ôćĺ  try {
264Ôćĺ    const data = runQuery(typedResource, params);
265Ôćĺ
266Ôćĺ    // Get or create subscription map for this connection
267Ôćĺ    let connSubs = subs.get(connectionId);
268Ôćĺ    if (!connSubs) {
269Ôćĺ      connSubs = new Map();
270Ôćĺ      subs.set(connectionId, connSubs);
271Ôćĺ    }
272Ôćĺ
273Ôćĺ    // Store subscription by client-assigned ID (replaces if same ID reused on reconnect)
274Ôćĺ    connSubs.set(id, { id, resource: typedResource, params });
275Ôćĺ
276Ôćĺ    // For messages: initialize cursor to current max seq
277Ôćĺ    if (typedResource === "messages") {
278Ôćĺ      const sessionId = readStringParam(params, "sessionId");
279Ôćĺ      const cursorKey = `${connectionId}:${id}`;
280Ôćĺ      if (sessionId) {
281Ôćĺ        try {
282Ôćĺ          const db = getDatabase();
283Ôćĺ          messageCursors.set(cursorKey, getMaxMessageSeq(db, sessionId));
284Ôćĺ        } catch {
285Ôćĺ          messageCursors.set(cursorKey, 0);
286Ôćĺ        }
287Ôćĺ      }
288Ôćĺ    }
289Ôćĺ
290Ôćĺ    sendFrame(connectionId, { type: "q:snapshot", id, data });
291Ôćĺ  } catch (err) {
292Ôćĺ    sendFrame(connectionId, {
293Ôćĺ      type: "q:error",
294Ôćĺ      id,
295Ôćĺ      code: "SUBSCRIBE_ERROR",
296Ôćĺ      message: err instanceof Error ? err.message : "Subscribe failed",
297Ôćĺ    });
298Ôćĺ  }
299Ôćĺ}
300Ôćĺ
301Ôćĺfunction handleUnsubscribe(connectionId: string, msg: UnsubscribeFrameInput): void {
302Ôćĺ  const { id } = msg;
303Ôćĺ
304Ôćĺ  const connSubs = subs.get(connectionId);
305Ôćĺ  if (!connSubs) return;
306Ôćĺ
307Ôćĺ  const sub = connSubs.get(id);
308Ôćĺ  if (sub) {
309Ôćĺ    // Clean up message cursor
310Ôćĺ    if (sub.resource === "messages") {
311Ôćĺ      messageCursors.delete(`${connectionId}:${id}`);
312Ôćĺ    }
313Ôćĺ    connSubs.delete(id);
314Ôćĺ    if (connSubs.size === 0) subs.delete(connectionId);
315Ôćĺ  }
316Ôćĺ}
317Ôćĺ
318Ôćĺfunction handleMutate(connectionId: string, msg: MutateFrameInput): void {
319Ôćĺ  const { id, action, params } = msg;
320Ôćĺ
321Ôćĺ  try {
322Ôćĺ    const result = runMutation(action, params);
323Ôćĺ    sendFrame(connectionId, {
324Ôćĺ      type: "q:mutate_result",
325Ôćĺ      id,
326Ôćĺ      success: true,
327Ôćĺ      data: result,
328Ôćĺ    });
329Ôćĺ  } catch (err) {
330Ôćĺ    sendFrame(connectionId, {
331Ôćĺ      type: "q:mutate_result",
332Ôćĺ      id,
333Ôćĺ      success: false,
334Ôćĺ      error: err instanceof Error ? err.message : "Mutation failed",
335Ôćĺ    });
336Ôćĺ  }
337Ôćĺ}
338Ôćĺ
339Ôćĺasync function handleCommand(connectionId: string, msg: CommandFrameInput): Promise<void> {
340Ôćĺ  const { id, command, params } = msg;
341Ôćĺ
342Ôćĺ  try {
343Ôćĺ    const result = await runCommand(toCommandName(command), params);
344Ôćĺ    sendFrame(connectionId, {
345Ôćĺ      type: "q:command_ack",
346Ôćĺ      id,
347Ôćĺ      accepted: true,
348Ôćĺ      ...result,
349Ôćĺ    } satisfies QServerFrame);
350Ôćĺ  } catch (err) {
351Ôćĺ    sendFrame(connectionId, {
352Ôćĺ      type: "q:command_ack",
353Ôćĺ      id,
354Ôćĺ      accepted: false,
355Ôćĺ      error: err instanceof Error ? err.message : "Command failed",
356Ôćĺ    } satisfies QServerFrame);
357Ôćĺ  }
358Ôćĺ}
