360Ôćĺ// ---- Tool Response Handler ----
361Ôćĺ
362Ôćĺfunction handleToolResponse(msg: QueryParams): void {
363Ôćĺ  const requestId = typeof msg.requestId === "string" ? msg.requestId : undefined;
364Ôćĺ  if (!requestId) {
365Ôćĺ    console.error("[QueryEngine] q:tool_response missing requestId");
366Ôćĺ    return;
367Ôćĺ  }
368Ôćĺ
369Ôćĺ  if ("error" in msg && msg.error !== undefined) {
370Ôćĺ    const errorStr = typeof msg.error === "string" ? msg.error : JSON.stringify(msg.error);
371Ôćĺ    const resolved = rejectToolRelay(requestId, errorStr);
372Ôćĺ    if (!resolved) {
373Ôćĺ      console.warn(`[QueryEngine] q:tool_response for unknown requestId=${requestId} (error)`);
374Ôćĺ    }
375Ôćĺ  } else {
376Ôćĺ    const resolved = resolveToolRelay(requestId, msg.result);
377Ôćĺ    if (!resolved) {
378Ôćĺ      console.warn(`[QueryEngine] q:tool_response for unknown requestId=${requestId} (result)`);
379Ôćĺ    }
380Ôćĺ  }
381Ôćĺ}
382Ôćĺ
383Ôćĺ// ---- Query Dispatch ----
384Ôćĺ
385Ôćĺfunction runQuery(resource: QueryResource, params: QueryParams): unknown {
386Ôćĺ  const db = getDatabase();
387Ôćĺ
388Ôćĺ  return match(resource)
389Ôćĺ    .with("workspaces", () => {
390Ôćĺ      // Return RepoGroup[] shape matching GET /workspaces/by-repo
391Ôćĺ      const state = readStringParam(params, "state") ?? "ready,initializing";
392Ôćĺ      const workspaces = getWorkspacesByRepo(db, state);
393Ôćĺ
394Ôćĺ      const grouped: Record<
395Ôćĺ        string,
396Ôćĺ        { repo_id: string; repo_name: string; sort_order: number; workspaces: unknown[] }
397Ôćĺ      > = {};
398Ôćĺ      workspaces.forEach((workspace) => {
399Ôćĺ        const repoId = workspace.repository_id || "unknown";
400Ôćĺ        if (!grouped[repoId]) {
401Ôćĺ          grouped[repoId] = {
402Ôćĺ            repo_id: repoId,
403Ôćĺ            repo_name: workspace.repo_name || "Unknown",
404Ôćĺ            sort_order: workspace.repo_sort_order ?? 999,
405Ôćĺ            workspaces: [],
406Ôćĺ          };
407Ôćĺ        }
408Ôćĺ        grouped[repoId].workspaces.push({
409Ôćĺ          ...workspace,
410Ôćĺ          workspace_path: computeWorkspacePath(workspace),
411Ôćĺ        });
412Ôćĺ      });
413Ôćĺ
414Ôćĺ      // Backfill repos that have no matching workspaces (e.g. all archived)
415Ôćĺ      const allRepos = getAllRepositorySummaries(db);
416Ôćĺ      for (const repo of allRepos) {
417Ôćĺ        if (!grouped[repo.id]) {
418Ôćĺ          grouped[repo.id] = {
419Ôćĺ            repo_id: repo.id,
420Ôćĺ            repo_name: repo.name,
421Ôćĺ            sort_order: repo.sort_order ?? 999,
422Ôćĺ            workspaces: [],
423Ôćĺ          };
424Ôćĺ        }
425Ôćĺ      }
426Ôćĺ
427Ôćĺ      return Object.values(grouped).sort((a, b) => a.sort_order - b.sort_order);
428Ôćĺ    })
429Ôćĺ    .with("stats", () => getStats(db))
430Ôćĺ    .with("sessions", () => {
431Ôćĺ      const workspaceId = readStringParam(params, "workspaceId");
432Ôćĺ      if (!workspaceId) throw new Error("sessions requires workspaceId param");
433Ôćĺ      return getSessionsByWorkspaceId(db, workspaceId);
434Ôćĺ    })
435Ôćĺ    .with("session", () => {
436Ôćĺ      const sessionId = readStringParam(params, "sessionId");
437Ôćĺ      if (!sessionId) throw new Error("session requires sessionId param");
438Ôćĺ      return getSessionById(db, sessionId);
439Ôćĺ    })
440Ôćĺ    .with("messages", () => {
441Ôćĺ      const sessionId = readStringParam(params, "sessionId");
442Ôćĺ      if (!sessionId) throw new Error("messages requires sessionId param");
443Ôćĺ
444Ôćĺ      const rows = getMessages(db, sessionId, {
445Ôćĺ        limit: readNumberParam(params, "limit") ?? 50,
446Ôćĺ        before: readNumberParam(params, "before"),
447Ôćĺ        after: readNumberParam(params, "after"),
448Ôćĺ      });
449Ôćĺ
450Ôćĺ      const hasOlder = rows.length > 0 ? hasOlderMessages(db, sessionId, rows[0].seq) : false;
451Ôćĺ      const hasNewer =
452Ôćĺ        rows.length > 0 ? hasNewerMessages(db, sessionId, rows[rows.length - 1].seq) : false;
453Ôćĺ
454Ôćĺ      return { messages: rows, has_older: hasOlder, has_newer: hasNewer };
455Ôćĺ    })
456Ôćĺ    .exhaustive();
457Ôćĺ}
458Ôćĺ
459Ôćĺ// ---- Mutation Dispatch ----
460Ôćĺ
461Ôćĺfunction runMutation(action: string, params: QueryParams): unknown {
462Ôćĺ  const typedAction = toMutationName(action);
463Ôćĺ
464Ôćĺ  return match(typedAction)
465Ôćĺ    .with("archiveWorkspace", () => {
466Ôćĺ      const db = getDatabase();
467Ôćĺ      const workspaceId = readStringParam(params, "workspaceId");
468Ôćĺ      if (!workspaceId) throw new Error("archiveWorkspace requires workspaceId");
469Ôćĺ
470Ôćĺ      const workspace = getWorkspaceRaw(db, workspaceId);
471Ôćĺ      if (!workspace) throw new Error("Workspace not found");
472Ôćĺ
473Ôćĺ      db.prepare("UPDATE workspaces SET state = 'archived' WHERE id = ?").run(workspaceId);
474Ôćĺ      autoProgressStatus(workspaceId, "done", { force: true });
475Ôćĺ      invalidate(["workspaces", "stats"]);
476Ôćĺ      return { success: true };
477Ôćĺ    })
478Ôćĺ    .with("updateWorkspaceTitle", () => {
479Ôćĺ      const db = getDatabase();
480Ôćĺ      const workspaceId = readStringParam(params, "workspaceId");
481Ôćĺ      const title = readStringParam(params, "title");
482Ôćĺ      if (!workspaceId || title === undefined) {
483Ôćĺ        throw new Error("updateWorkspaceTitle requires workspaceId and title");
484Ôćĺ      }
485Ôćĺ
486Ôćĺ      const workspace = getWorkspaceRaw(db, workspaceId);
487Ôćĺ      if (!workspace) throw new Error("Workspace not found");
488Ôćĺ
489Ôćĺ      db.prepare("UPDATE workspaces SET title = ? WHERE id = ?").run(title, workspaceId);
490Ôćĺ      invalidate(["workspaces"]);
491Ôćĺ      return { success: true };
492Ôćĺ    })
493Ôćĺ    .with("updateWorkspaceStatus", () => {
494Ôćĺ      const workspaceId = readStringParam(params, "workspaceId");
495Ôćĺ      const status = readStringParam(params, "status");
496Ôćĺ      if (!workspaceId || !status) {
497Ôćĺ        throw new Error("updateWorkspaceStatus requires workspaceId and status");
498Ôćĺ      }
499Ôćĺ      setWorkspaceStatus(workspaceId, status as WorkspaceStatus);
500Ôćĺ      invalidate(["workspaces", "stats"]);
501Ôćĺ      return { success: true };
502Ôćĺ    })
503Ôćĺ    .exhaustive();
504Ôćĺ}
505Ôćĺ
506Ôćĺ// ---- Message Delta Push ----
507Ôćĺ
508Ôćĺfunction pushMessageDelta(connectionId: string, subId: string, params: QueryParams): void {
509Ôćĺ  const sessionId = readStringParam(params, "sessionId");
510Ôćĺ  if (!sessionId) return;
511Ôćĺ
512Ôćĺ  const cursorKey = `${connectionId}:${subId}`;
513Ôćĺ  const lastSeq = messageCursors.get(cursorKey) ?? 0;
514Ôćĺ
515Ôćĺ  try {
516Ôćĺ    const db = getDatabase();
517Ôćĺ    const newMessages = getMessagesDelta(db, sessionId, lastSeq);
518Ôćĺ
519Ôćĺ    if (newMessages.length === 0) return;
520Ôćĺ
521Ôćĺ    const maxSeq = newMessages[newMessages.length - 1].seq;
522Ôćĺ    messageCursors.set(cursorKey, maxSeq);
523Ôćĺ
524Ôćĺ    sendFrame(connectionId, {
525Ôćĺ      type: "q:delta",
526Ôćĺ      id: subId,
527Ôćĺ      upserted: newMessages,
528Ôćĺ      cursor: maxSeq,
529Ôćĺ    });
530Ôćĺ  } catch (err) {
531Ôćĺ    console.error(`[QueryEngine] Message delta push failed:`, err);
532Ôćĺ  }
533Ôćĺ}
