535Ôćĺ// ---- Helpers ----
536Ôćĺ
537Ôćĺfunction sendFrame(connectionId: string, frame: QServerFrame): void {
538Ôćĺ  const conn = getConnection(connectionId);
539Ôćĺ  if (!conn) return;
540Ôćĺ  try {
541Ôćĺ    conn.ws.send(JSON.stringify(frame));
542Ôćĺ  } catch {
543Ôćĺ    // Connection may have closed
544Ôćĺ  }
545Ôćĺ}
546Ôćĺ
547Ôćĺfunction parseResourceFrame(msg: QueryParams): ResourceFrameInput {
